fn deserialize_agent_reply_to_user<'de, D>(deserializer: D) -> Result<String, D::Error>
where
    D: serde::Deserializer<'de>,
{
    let value = serde_json::Value::deserialize(deserializer)?;
    Ok(agent_reply_text_from_value(&value))
}

fn deserialize_agent_goal_envelope<'de, D>(
    deserializer: D,
) -> Result<Option<GoalEnvelopeProposal>, D::Error>
where
    D: serde::Deserializer<'de>,
{
    Option::<serde_json::Value>::deserialize(deserializer)?
        .map(GoalEnvelopeProposal::parse_value)
        .transpose()
        .map_err(serde::de::Error::custom)
}

fn deserialize_agent_task_capability_proposal<'de, D>(
    deserializer: D,
) -> Result<Option<TaskCapabilityProposal>, D::Error>
where
    D: serde::Deserializer<'de>,
{
    Option::<serde_json::Value>::deserialize(deserializer)?
        .map(TaskCapabilityProposal::parse_value)
        .transpose()
        .map_err(serde::de::Error::custom)
}

fn deserialize_agent_protocol_version<'de, D>(deserializer: D) -> Result<Option<String>, D::Error>
where
    D: serde::Deserializer<'de>,
{
    let value = Option::<serde_json::Value>::deserialize(deserializer)?;
    Ok(value.and_then(|value| match value {
        serde_json::Value::Null => None,
        serde_json::Value::String(text) => Some(text),
        serde_json::Value::Bool(value) => Some(value.to_string()),
        serde_json::Value::Number(value) => Some(value.to_string()),
        serde_json::Value::Array(_) | serde_json::Value::Object(_) => {
            Some(serde_json::to_string(&value).unwrap_or_default())
        }
    }))
}

fn deserialize_agent_subagent_plan<'de, D>(
    deserializer: D,
) -> Result<Vec<AgentSubtaskPlanItem>, D::Error>
where
    D: serde::Deserializer<'de>,
{
    Ok(Option::<Vec<AgentSubtaskPlanItem>>::deserialize(deserializer)?.unwrap_or_default())
}

fn agent_reply_text_from_value(value: &serde_json::Value) -> String {
    match value {
        serde_json::Value::String(text) => text.clone(),
        serde_json::Value::Object(object) => ["content", "text", "message", "body"]
            .iter()
            .find_map(|key| object.get(*key).and_then(serde_json::Value::as_str))
            .unwrap_or_default()
            .to_string(),
        _ => String::new(),
    }
}

fn deserialize_agent_action_content<'de, D>(deserializer: D) -> Result<Option<String>, D::Error>
where
    D: serde::Deserializer<'de>,
{
    let value = Option::<serde_json::Value>::deserialize(deserializer)?;
    Ok(value.and_then(|value| match value {
        serde_json::Value::Null => None,
        serde_json::Value::String(text) => Some(text),
        serde_json::Value::Bool(value) => Some(value.to_string()),
        serde_json::Value::Number(value) => Some(value.to_string()),
        serde_json::Value::Array(_) | serde_json::Value::Object(_) => {
            Some(serde_json::to_string(&value).unwrap_or_default())
        }
    }))
}

