fn run_queued_agent_chat_with_clients_and_api_keys_and_computer_use(
    store: &Mutex<EventStore>,
    transport: &impl DeepSeekChatCompletionTransport,
    cache: &DeepSeekMemoryChatCompletionCache,
    api_keys: &[String],
    run_id: Option<Uuid>,
    execution_prompt: Option<String>,
    worker_id: String,
    model_route: ModelRoute,
    thinking_level: ThinkingLevel,
    access_mode: AccessMode,
    runtime_context: AgentChatRuntimeContext,
    pricing_settings: Option<&DeepSeekPricingSettings>,
    file_client: &impl FileContentClient,
    file_write_client: &impl AgentWritableArtifactClient,
    search_client: &impl NetworkSearchClient,
    browser_client: &impl BrowserPageClient,
    computer_use_client: &(impl ComputerScreenshotClient + ComputerControlClient),
) -> Result<Option<AgentRunWorkerResult>, String> {
    if let (Some(run_id), Some(execution_prompt)) = (run_id, execution_prompt.as_ref()) {
        let execution_prompt = execution_prompt.trim();
        if !execution_prompt.is_empty() {
            let store = store.lock().map_err(|_| lock_error())?;
            let record = read_agent_run_record(&store, run_id)?;
            if record.execution_prompt.as_deref() != Some(execution_prompt) {
                let context = AgentRunExecutionContext::new(run_id, execution_prompt.to_string())
                    .map_err(event_store_error)?;
                store
                    .append_agent_run_execution_context(&context)
                    .map_err(event_store_error)?;
            }
        }
    }
    let Some(claimed) = ({
        let store = store.lock().map_err(|_| lock_error())?;
        match run_id {
            Some(run_id) => Some(
                store
                    .claim_agent_run(run_id, worker_id.clone(), AGENT_RUN_WORKER_LEASE_SECONDS)
                    .map_err(event_store_error)?,
            ),
            None => store
                .claim_next_agent_run(worker_id.clone(), AGENT_RUN_WORKER_LEASE_SECONDS)
                .map_err(event_store_error)?,
        }
    }) else {
        return Ok(None);
    };
    let run_id = claimed.id;
    let base_prompt = execution_prompt
        .map(|prompt| prompt.trim().to_string())
        .filter(|prompt| !prompt.is_empty())
        .or_else(|| claimed.execution_prompt.clone())
        .unwrap_or_else(|| claimed.prompt.clone());
    let prompt = expert_attempt_execution_prompt(store, &claimed, &base_prompt)?;
    let mut runtime_context = runtime_context;
    runtime_context.active_run_id = Some(run_id);
    runtime_context.subagent_read_only =
        claimed.role == crate::kernel::agent_run::AgentRunRole::Subagent;
    runtime_context.expert_capabilities = claimed
        .expert_contract
        .as_ref()
        .map(|contract| contract.capabilities.clone());
    let expert_staging_root = runtime_context.expert_staging_root.clone();

    record_agent_run_worker_step(
        store,
        run_id,
        1,
        AgentRunStepStatus::Running,
        "DeepSeek",
        "Background worker claimed the queued run and started DeepSeek execution.",
    )?;

    let (response_result, heartbeat_result) = run_with_agent_run_lease_heartbeat(
        store,
        run_id,
        &worker_id,
        AGENT_RUN_WORKER_LEASE_SECONDS,
        StdDuration::from_secs(AGENT_RUN_WORKER_HEARTBEAT_SECONDS),
        || {
            run_agent_chat_with_clients_and_api_keys_and_computer_use(
                store,
                transport,
                cache,
                api_keys,
                AgentChatRequest {
                    prompt,
                    model_route,
                    thinking_level,
                    access_mode,
                },
                runtime_context,
                pricing_settings,
                file_client,
                file_write_client,
                search_client,
                browser_client,
                computer_use_client,
            )
        },
    );
    let response_result = match (response_result, heartbeat_result) {
        (response_result, Ok(())) => response_result,
        (Ok(_), Err(heartbeat_error)) => Err(heartbeat_error),
        (Err(error), Err(heartbeat_error)) => Err(format!(
            "{error}; additionally failed to renew the agent run lease: {heartbeat_error}"
        )),
    };

    match response_result {
        Ok(response) => {
            record_agent_run_worker_step(
                store,
                run_id,
                1,
                AgentRunStepStatus::Completed,
                "DeepSeek",
                "DeepSeek execution completed and the response was recorded.",
            )?;
            let cancel_requested = agent_run_cancel_requested(store, run_id)?;
            let record = if cancel_requested {
                finish_agent_run_from_worker(
                    store,
                    run_id,
                    AgentRunStatus::Cancelled,
                    Some(
                        "Agent run cancelled before committing the completed response.".to_string(),
                    ),
                    None,
                )?
            } else if claimed.role == crate::kernel::agent_run::AgentRunRole::Parent
                && !response.subagent_plan.is_empty()
                && !agent_run_has_subagents(store, run_id)?
            {
                {
                    let store = store.lock().map_err(|_| lock_error())?;
                    store
                        .append_expert_team_runs(run_id, response.subagent_plan.clone())
                        .map_err(event_store_error)?;
                }
                transition_agent_run_from_worker(
                    store,
                    run_id,
                    AgentRunStatus::Blocked,
                    "Parent run is waiting for its parallel Subagents to finish.".to_string(),
                    None,
                )?
            } else if claimed.expert_contract.is_some() {
                let result = build_expert_attempt_result(
                    store,
                    &claimed,
                    &response,
                    expert_staging_root.as_deref(),
                )?;
                let passed = result.passed();
                {
                    let store = store.lock().map_err(|_| lock_error())?;
                    store
                        .append_expert_attempt_result(&result)
                        .map_err(event_store_error)?;
                }
                if passed {
                    finish_agent_run_from_worker(
                        store,
                        run_id,
                        AgentRunStatus::Completed,
                        Some(result.summary.clone()),
                        None,
                    )?
                } else {
                    let failed_gates = result
                        .quality_gates
                        .iter()
                        .filter(|gate| !gate.passed)
                        .map(|gate| gate.code.as_str())
                        .collect::<Vec<_>>()
                        .join(", ");
                    finish_agent_run_from_worker(
                        store,
                        run_id,
                        AgentRunStatus::Failed,
                        None,
                        Some(format!("Expert quality gates failed: {failed_gates}")),
                    )?
                }
            } else if claimed.role == crate::kernel::agent_run::AgentRunRole::Subagent
                && response.proposed_actions.iter().any(|action| {
                    action.execution_state == "blocked"
                        && action.blocked_reason.as_deref().is_some_and(|reason| {
                            reason.contains("Background Subagents are read-only")
                        })
                })
            {
                finish_agent_run_from_worker(
                    store,
                    run_id,
                    AgentRunStatus::Failed,
                    None,
                    Some(
                        "Subagent proposed a mutating or foreground action that must be mediated by the parent Agent."
                            .to_string(),
                    ),
                )?
            } else if let Some((status, reason, tool_invocation_id)) =
                agent_run_waiting_outcome_from_response(&response)
            {
                transition_agent_run_from_worker(store, run_id, status, reason, tool_invocation_id)?
            } else {
                finish_agent_run_from_worker(
                    store,
                    run_id,
                    AgentRunStatus::Completed,
                    Some(response.content.clone()),
                    None,
                )?
            };
            Ok(Some(AgentRunWorkerResult { record, response }))
        }
        Err(error) => {
            let record_error = record_agent_run_worker_step(
                store,
                run_id,
                1,
                AgentRunStepStatus::Failed,
                "DeepSeek",
                format!("DeepSeek execution failed: {error}"),
            )
            .and_then(|_| {
                finish_agent_run_from_worker(
                    store,
                    run_id,
                    AgentRunStatus::Failed,
                    None,
                    Some(error.clone()),
                )
            })
            .err();
            if let Some(record_error) = record_error {
                return Err(format!(
                    "{error}; additionally failed to record agent run failure: {record_error}"
                ));
            }
            Err(error)
        }
    }
}

fn agent_run_has_subagents(store: &Mutex<EventStore>, parent_run_id: Uuid) -> Result<bool, String> {
    let store = store.lock().map_err(|_| lock_error())?;
    Ok(store
        .list_agent_run_records()
        .map_err(event_store_error)?
        .iter()
        .any(|record| record.parent_run_id == Some(parent_run_id)))
}

fn expert_attempt_execution_prompt(
    store: &Mutex<EventStore>,
    claimed: &AgentRunRecord,
    base_prompt: &str,
) -> Result<String, String> {
    let Some(contract) = claimed.expert_contract.as_ref() else {
        return Ok(base_prompt.to_string());
    };
    let records = store
        .lock()
        .map_err(|_| lock_error())?
        .list_agent_run_records()
        .map_err(event_store_error)?;
    let dependencies = contract
        .depends_on
        .iter()
        .map(|dependency_key| {
            let latest = records
                .iter()
                .filter(|record| record.parent_run_id == Some(contract.parent_run_id))
                .filter(|record| {
                    record.expert_contract.as_ref().is_some_and(|candidate| {
                        candidate.key.eq_ignore_ascii_case(dependency_key)
                    })
                })
                .max_by_key(|record| {
                    record
                        .expert_contract
                        .as_ref()
                        .map(|candidate| candidate.attempt)
                        .unwrap_or(0)
                })
                .ok_or_else(|| format!("expert dependency `{dependency_key}` is missing"))?;
            let result = latest.expert_result.as_ref().ok_or_else(|| {
                format!("expert dependency `{dependency_key}` has no durable result")
            })?;
            if latest.status != AgentRunStatus::Completed || !result.passed() {
                return Err(format!(
                    "expert dependency `{dependency_key}` did not pass its quality gate"
                ));
            }
            let claims = result
                .claims
                .iter()
                .take(8)
                .map(|claim| {
                    format!(
                        "    claim={} stance={:?} statement={}",
                        claim.key,
                        claim.stance,
                        compact_tool_evidence_excerpt(&claim.statement)
                    )
                })
                .collect::<Vec<_>>()
                .join("\n");
            let evidence = result
                .evidence
                .iter()
                .filter(|evidence| evidence.verified)
                .take(8)
                .map(|evidence| {
                    format!(
                        "    evidence={} kind={} reference={} summary={}",
                        evidence.id,
                        evidence.kind,
                        compact_tool_evidence_excerpt(&evidence.reference),
                        compact_tool_evidence_excerpt(&evidence.summary)
                    )
                })
                .collect::<Vec<_>>()
                .join("\n");
            Ok(format!(
                "- key={} role={:?} attempt={} revision={}\n  summary={}\n  evidence={} conflicts={} missing={}\n  claims:\n{}\n  verified evidence:\n{}",
                dependency_key,
                result.role,
                result.attempt,
                result.output_revision,
                result.summary,
                result.evidence.len(),
                result.unresolved_conflicts.len(),
                result.missing_evidence.len(),
                if claims.is_empty() { "    (none)" } else { claims.as_str() },
                if evidence.is_empty() {
                    "    (none)"
                } else {
                    evidence.as_str()
                }
            ))
        })
        .collect::<Result<Vec<_>, String>>()?
        .join("\n");
    Ok(format!(
        "You are the {:?} expert in one bounded DS Agent Expert Team. This is attempt {} for key `{}`. Do not create another team or subagent plan. Stay inside capabilities {:?}. Child actions are read-only; production content may only be returned as expert_output.staged_content for DS Agent to write into managed run-scoped staging. Review cannot mutate content and must bind its verdict to the exact dependency revision. Preserve contradictions, missing evidence, and uncertainty. Return structured expert_output with summary and evidence-linked claims; production must include staged_content and a safe relative filename; review must include target_revision, decision, and findings.\n\nImmutable budgets: elapsed_ms<={} tool_calls<={} tokens<={} output_bytes<={} staged_bytes<={}.\nParent input revision: {}.\n\nAssignment:\n{}\n\nPassed dependency results:\n{}",
        contract.role,
        contract.attempt,
        contract.key,
        contract.capabilities,
        contract.budget.max_elapsed_ms,
        contract.budget.max_tool_calls,
        contract.budget.max_tokens,
        contract.budget.max_output_bytes,
        contract.budget.max_staged_bytes,
        contract.parent_input_revision,
        base_prompt,
        if dependencies.is_empty() {
            "(none)"
        } else {
            dependencies.as_str()
        }
    ))
}

fn build_expert_attempt_result(
    store: &Mutex<EventStore>,
    claimed: &AgentRunRecord,
    response: &AgentChatResponse,
    staging_base: Option<&Path>,
) -> Result<ExpertAttemptResult, String> {
    let contract = claimed
        .expert_contract
        .as_ref()
        .ok_or_else(|| "expert result requires an immutable attempt contract".to_string())?;
    let output = response.expert_output.clone().unwrap_or_default();
    let claims = output
        .claims
        .iter()
        .take(crate::kernel::expert_team::EXPERT_TEAM_MAX_CLAIMS)
        .cloned()
        .collect::<Vec<_>>();
    let (tool_invocations, records) = {
        let store = store.lock().map_err(|_| lock_error())?;
        (
            store
                .list_tool_invocations()
                .map_err(event_store_error)?
                .into_iter()
                .filter(|invocation| invocation.run_id == Some(claimed.id))
                .collect::<Vec<_>>(),
            store.list_agent_run_records().map_err(event_store_error)?,
        )
    };
    let evidence = deduplicate_evidence(
        tool_invocations
            .iter()
            .flat_map(|invocation| {
                invocation
                    .evidence
                    .iter()
                    .map(move |evidence| ExpertEvidenceRef {
                        id: String::new(),
                        kind: evidence.kind.clone(),
                        reference: evidence.reference.clone(),
                        summary: evidence.summary.clone(),
                        verified: invocation.status == ToolExecutionStatus::Succeeded
                            && invocation.verification.passed,
                    })
            })
            .collect(),
    );
    let evidence_ids = evidence
        .iter()
        .flat_map(|item| [item.id.as_str(), item.reference.as_str()])
        .collect::<std::collections::HashSet<_>>();
    let mut missing_evidence = Vec::new();
    for claim in &claims {
        if claim.evidence_refs.is_empty() {
            missing_evidence.push(format!("claim `{}` has no evidence reference", claim.key));
        } else {
            for reference in &claim.evidence_refs {
                if !evidence_ids.contains(reference.trim()) {
                    missing_evidence.push(format!(
                        "claim `{}` references unknown evidence `{}`",
                        claim.key, reference
                    ));
                }
            }
        }
    }
    missing_evidence.sort();
    missing_evidence.dedup();
    let unresolved_conflicts = unresolved_claim_conflicts(&claims);

    let serialized_output = serde_json::to_string(&output).map_err(event_store_error)?;
    let output_bytes = u64::try_from(response.content.len() + serialized_output.len())
        .map_err(|_| "expert output byte count overflow".to_string())?;
    let mut staging = None;
    let mut staging_error = None;
    if contract.role == ExpertRole::Production {
        match (
            staging_base,
            output.staged_content.as_deref(),
            output.staged_relative_path.as_deref().or(Some("draft.md")),
        ) {
            (Some(base), Some(content), Some(relative_path)) => {
                match stage_expert_output(base, contract, relative_path, content) {
                    Ok(manifest) => staging = Some(manifest),
                    Err(error) => staging_error = Some(error),
                }
            }
            _ => staging_error = Some("production expert returned no staged content".to_string()),
        }
    }
    let staged_bytes = staging.as_ref().map(|manifest| manifest.bytes).unwrap_or(0);
    let tokens = response.total_tokens.unwrap_or_else(|| {
        response
            .prompt_tokens
            .unwrap_or(0)
            .saturating_add(response.completion_tokens.unwrap_or(0))
    });
    let usage = ExpertAttemptUsage {
        elapsed_ms: u64::try_from(response.elapsed_ms).unwrap_or(u64::MAX),
        tool_calls: u32::try_from(tool_invocations.len()).unwrap_or(u32::MAX),
        tokens,
        output_bytes,
        staged_bytes,
    };
    let verified_sources = evidence.iter().filter(|item| item.verified).count();
    let mut quality_gates = vec![
        ExpertQualityGate {
            code: "output_present".to_string(),
            passed: !response.content.trim().is_empty() || !output.summary.trim().is_empty(),
            detail: "expert returned a non-empty summary or response".to_string(),
        },
        ExpertQualityGate {
            code: "capability_scope".to_string(),
            passed: response
                .proposed_actions
                .iter()
                .all(|action| action.execution_state != "blocked"),
            detail: "all expert actions remained inside the immutable capability scope".to_string(),
        },
        ExpertQualityGate {
            code: "elapsed_budget".to_string(),
            passed: usage.elapsed_ms <= contract.budget.max_elapsed_ms,
            detail: format!(
                "elapsed {} / {} ms",
                usage.elapsed_ms, contract.budget.max_elapsed_ms
            ),
        },
        ExpertQualityGate {
            code: "tool_budget".to_string(),
            passed: usage.tool_calls <= contract.budget.max_tool_calls,
            detail: format!(
                "tool calls {} / {}",
                usage.tool_calls, contract.budget.max_tool_calls
            ),
        },
        ExpertQualityGate {
            code: "token_budget".to_string(),
            passed: usage.tokens <= contract.budget.max_tokens,
            detail: format!("tokens {} / {}", usage.tokens, contract.budget.max_tokens),
        },
        ExpertQualityGate {
            code: "output_budget".to_string(),
            passed: usage.output_bytes <= contract.budget.max_output_bytes,
            detail: format!(
                "output bytes {} / {}",
                usage.output_bytes, contract.budget.max_output_bytes
            ),
        },
        ExpertQualityGate {
            code: "claims".to_string(),
            passed: !contract.output_contract.require_claims || !claims.is_empty(),
            detail: format!("{} structured claims", claims.len()),
        },
        ExpertQualityGate {
            code: "evidence".to_string(),
            passed: verified_sources >= contract.output_contract.min_evidence_sources
                && missing_evidence.is_empty(),
            detail: format!(
                "{} verified sources; {} missing claim links",
                verified_sources,
                missing_evidence.len()
            ),
        },
        ExpertQualityGate {
            code: "conflicts".to_string(),
            passed: !contract.output_contract.fail_on_unresolved_conflict
                || unresolved_conflicts.is_empty(),
            detail: format!("{} unresolved conflicts", unresolved_conflicts.len()),
        },
    ];
    if contract.output_contract.require_staged_output {
        quality_gates.push(ExpertQualityGate {
            code: "managed_staging".to_string(),
            passed: staging.is_some() && staging_error.is_none(),
            detail: staging_error
                .unwrap_or_else(|| format!("{} staged bytes recorded", staged_bytes)),
        });
    }
    if contract.output_contract.require_review {
        let latest_production = records
            .iter()
            .filter(|record| record.parent_run_id == Some(contract.parent_run_id))
            .filter(|record| {
                record
                    .expert_contract
                    .as_ref()
                    .is_some_and(|candidate| candidate.role == ExpertRole::Production)
            })
            .filter_map(|record| {
                record
                    .expert_contract
                    .as_ref()
                    .zip(record.expert_result.as_ref())
                    .map(|(candidate, result)| (candidate.attempt, result))
            })
            .max_by_key(|(attempt, _)| *attempt)
            .map(|(_, result)| result);
        let exact_review = output.review.as_ref().is_some_and(|review| {
            latest_production.is_some_and(|production| {
                review.target_revision == production.output_revision
                    && review.decision == ExpertReviewDecision::Accept
            })
        });
        quality_gates.push(ExpertQualityGate {
            code: "exact_revision_review".to_string(),
            passed: exact_review,
            detail: if exact_review {
                "review accepted the exact current production revision".to_string()
            } else {
                "review did not accept the exact current production revision".to_string()
            },
        });
    }
    let output_revision = staging
        .as_ref()
        .map(|manifest| manifest.sha256.clone())
        .unwrap_or_else(|| sha256_text(&format!("{}\n{}", response.content, serialized_output)));
    let passed = quality_gates.iter().all(|gate| gate.passed);
    let external_effect_state = if staging.is_some() {
        ExpertExternalEffectState::ManagedStagingOnly
    } else if tool_invocations.is_empty() {
        ExpertExternalEffectState::None
    } else {
        ExpertExternalEffectState::VerifiedReadOnly
    };
    Ok(ExpertAttemptResult {
        id: Uuid::new_v4(),
        run_id: claimed.id,
        parent_run_id: contract.parent_run_id,
        key: contract.key.clone(),
        role: contract.role,
        attempt: contract.attempt,
        parent_input_revision: contract.parent_input_revision.clone(),
        output_revision,
        summary: if output.summary.trim().is_empty() {
            response.content.clone()
        } else {
            output.summary
        },
        claims,
        evidence,
        unresolved_conflicts,
        missing_evidence,
        usage,
        quality_gates,
        staging,
        review: output.review,
        external_effect_state,
        retry_eligible: !passed
            && contract.attempt < contract.retry_policy.max_attempts
            && external_effect_state != ExpertExternalEffectState::Uncertain,
        recorded_at: Utc::now(),
    })
}

fn run_with_agent_run_lease_heartbeat<T>(
    store: &Mutex<EventStore>,
    run_id: Uuid,
    worker_id: &str,
    lease_seconds: i64,
    heartbeat_interval: StdDuration,
    operation: impl FnOnce() -> T,
) -> (T, Result<(), String>) {
    std::thread::scope(|scope| {
        let (stop_tx, stop_rx) = std::sync::mpsc::sync_channel(1);
        let heartbeat = scope.spawn(move || loop {
            match stop_rx.recv_timeout(heartbeat_interval) {
                Ok(()) | Err(std::sync::mpsc::RecvTimeoutError::Disconnected) => return Ok(()),
                Err(std::sync::mpsc::RecvTimeoutError::Timeout) => {
                    let event_store = store.lock().map_err(|_| lock_error())?;
                    event_store
                        .heartbeat_agent_run_lease(run_id, worker_id.to_string(), lease_seconds)
                        .map_err(event_store_error)?;
                }
            }
        });
        let output = operation();
        let _ = stop_tx.send(());
        let heartbeat_result = heartbeat
            .join()
            .map_err(|_| "agent run lease heartbeat thread panicked".to_string())
            .and_then(|result| result);
        (output, heartbeat_result)
    })
}

fn agent_run_cancel_requested(store: &Mutex<EventStore>, run_id: Uuid) -> Result<bool, String> {
    let store = store.lock().map_err(|_| lock_error())?;
    Ok(read_agent_run_record(&store, run_id)?.cancel_requested)
}

fn agent_run_waiting_outcome_from_response(
    response: &AgentChatResponse,
) -> Option<(AgentRunStatus, String, Option<Uuid>)> {
    if !response.missing_prerequisites.is_empty()
        || response
            .proposed_actions
            .iter()
            .any(|action| action.execution_state == "waiting_prerequisite")
    {
        let detail = response
            .missing_prerequisites
            .iter()
            .map(|prerequisite| prerequisite.message.trim())
            .filter(|message| !message.is_empty())
            .collect::<Vec<_>>()
            .join("; ");
        return Some((
            AgentRunStatus::WaitingForPrerequisite,
            if detail.is_empty() {
                "Agent run is waiting for a local prerequisite.".to_string()
            } else {
                format!("Agent run is waiting for prerequisites: {detail}")
            },
            response
                .proposed_actions
                .iter()
                .find_map(|action| action.capability_invocation_id),
        ));
    }

    if let Some(action) = response
        .proposed_actions
        .iter()
        .find(|action| action.execution_state == "needs_confirmation")
    {
        return Some((
            AgentRunStatus::WaitingForConfirmation,
            action
                .dispatch_note
                .clone()
                .unwrap_or_else(|| "Agent run is waiting for local confirmation.".to_string()),
            action.capability_invocation_id,
        ));
    }

    response
        .proposed_actions
        .iter()
        .find(|action| matches!(action.execution_state.as_str(), "blocked" | "failed"))
        .map(|action| {
            (
                AgentRunStatus::Blocked,
                action
                    .blocked_reason
                    .clone()
                    .or_else(|| action.dispatch_note.clone())
                    .unwrap_or_else(|| "Agent run was blocked by local policy.".to_string()),
                action.capability_invocation_id,
            )
        })
}

fn transition_agent_run_from_worker(
    store: &Mutex<EventStore>,
    run_id: Uuid,
    status: AgentRunStatus,
    reason: String,
    tool_invocation_id: Option<Uuid>,
) -> Result<AgentRunRecord, String> {
    let transition = AgentRunTransition::new(run_id, status, reason, tool_invocation_id)
        .map_err(event_store_error)?;
    let store = store.lock().map_err(|_| lock_error())?;
    store
        .append_agent_run_transition(&transition)
        .map_err(event_store_error)?;
    read_agent_run_record(&store, run_id)
}

fn record_agent_run_worker_step(
    store: &Mutex<EventStore>,
    run_id: Uuid,
    sequence: u32,
    status: AgentRunStepStatus,
    label: impl Into<String>,
    detail: impl Into<String>,
) -> Result<AgentRunRecord, String> {
    let step = AgentRunStepRecord::new(run_id, sequence, status, label.into(), detail.into())
        .map_err(event_store_error)?;
    let store = store.lock().map_err(|_| lock_error())?;
    store
        .append_agent_run_step(&step)
        .map_err(event_store_error)?;
    read_agent_run_record(&store, run_id)
}

fn finish_agent_run_from_worker(
    store: &Mutex<EventStore>,
    run_id: Uuid,
    status: AgentRunStatus,
    summary: Option<String>,
    error: Option<String>,
) -> Result<AgentRunRecord, String> {
    let finish = AgentRunFinish::new(run_id, status, summary, error).map_err(event_store_error)?;
    let store = store.lock().map_err(|_| lock_error())?;
    store
        .append_agent_run_finish(&finish)
        .map_err(event_store_error)?;
    read_agent_run_record(&store, run_id)
}

fn build_agent_tool_evidence_followup_prompt(
    original_user_prompt: &str,
    response: &AgentChatResponse,
) -> Option<String> {
    let needs_model_followup = response
        .proposed_actions
        .iter()
        .any(agent_action_needs_model_evidence_followup);
    let completed_actions = completed_agent_action_dispatch_summaries_for_model(response);

    if !needs_model_followup || completed_actions.is_empty() {
        return None;
    }

    Some(format!(
        "DS Agent completed local actions and collected tool evidence.\n\
         Original user message:\n{original_user_prompt}\n\n\
         Tool evidence from completed DS Agent actions:\n{}\n\n\
         Use only this completed evidence and the original user message to produce the final user-facing answer. Lead with the useful conclusion, answer in the user's language, and summarize evidence in ordinary language. Do not claim any unexecuted action succeeded. Do not expose internal action types, tool IDs, protocol or schema names, policy enums, target=/evidence=/output= fields, raw JSON, English verification receipts, or loop labels such as loop_mode, validators, stop_conditions, and matched_stop_conditions unless the user explicitly asked for technical details.",
        completed_actions.join("\n")
    ))
}

fn record_agent_context_receipts(
    store: &EventStore,
    response: &AgentChatResponse,
    model_route: &str,
    thinking_level: &str,
    access_mode: &str,
    soul_profile: Option<&AgentSoulProfileContext>,
    memory_context: &AgentMemoryRuntimeContext,
    memory_candidate_gate: &AgentMemoryCandidateGateReceipt,
    telemetry: &[DeepSeekChatTelemetry],
) -> Result<(), String> {
    let token_cache_state = operations_briefing_token_cache_context(telemetry);
    for action in response
        .proposed_actions
        .iter()
        .filter(|action| agent_action_needs_context_receipt(action))
    {
        let receipt = agent_context_receipt_for_action(
            action,
            model_route,
            thinking_level,
            access_mode,
            &token_cache_state,
            soul_profile,
            memory_context,
            memory_candidate_gate,
        );
        store
            .append_agent_context_receipt(&receipt)
            .map_err(event_store_error)?;
    }
    Ok(())
}

fn agent_action_needs_context_receipt(action: &AgentChatActionProposal) -> bool {
    action.capability_invocation_id.is_some() && agent_action_needs_model_evidence_followup(action)
}

fn agent_context_receipt_for_action(
    action: &AgentChatActionProposal,
    model_route: &str,
    thinking_level: &str,
    access_mode: &str,
    token_cache_state: &str,
    soul_profile: Option<&AgentSoulProfileContext>,
    memory_context: &AgentMemoryRuntimeContext,
    memory_candidate_gate: &AgentMemoryCandidateGateReceipt,
) -> AgentContextReceipt {
    let mut receipt = AgentContextReceipt::new(
        action.action_type.clone(),
        action.execution_state.clone(),
        model_route.to_string(),
        thinking_level.to_string(),
        token_cache_state.to_string(),
    );
    receipt.capability = action
        .capability
        .as_ref()
        .map(serialize_agent_chat_context_value);
    receipt.policy_decision = action
        .policy_decision
        .as_ref()
        .map(serialize_agent_chat_context_value);
    receipt.capability_invocation_id = action.capability_invocation_id;
    receipt.workflow_run_id = action.workflow_run_id;
    let loop_mode = classify_agent_action_loop_mode(
        &action.action_type,
        &action.execution_state,
        action.requires_confirmation,
        action.workflow_run_id.is_some(),
    );
    receipt.loop_mode = loop_mode.as_str().to_string();
    let loop_mode_descriptor = agent_loop_mode_descriptor(loop_mode);
    receipt.allowed_tools = loop_mode_descriptor
        .allowed_tools
        .iter()
        .map(|value| (*value).to_string())
        .collect();
    receipt.validators = loop_mode_descriptor
        .validators
        .iter()
        .map(|value| (*value).to_string())
        .collect();
    receipt.stop_conditions = loop_mode_descriptor
        .stop_conditions
        .iter()
        .map(|value| (*value).to_string())
        .collect();
    receipt.matched_stop_conditions = agent_context_matched_stop_conditions(action, loop_mode);
    receipt.confirmation_rule = loop_mode_descriptor.confirmation_rule.to_string();
    receipt.policy_constraints = agent_context_policy_constraints(action, access_mode);
    receipt.selected_evidence = agent_context_selected_evidence(action);
    let mut selected_memories = soul_profile
        .map(agent_soul_profile_receipt_line)
        .into_iter()
        .collect::<Vec<_>>();
    if agent_memory_context_has_retrieval_receipt(memory_context) {
        selected_memories.push(agent_memory_retrieval_receipt_line(memory_context));
    }
    selected_memories.extend(
        memory_context
            .selected
            .iter()
            .map(agent_selected_memory_receipt_line),
    );
    receipt.selected_memories = selected_memories;
    receipt.memory_candidate_gate =
        agent_memory_candidate_gate_receipt_lines(memory_candidate_gate);
    receipt.validation_results = agent_context_validation_results(action);
    if memory_candidate_gate.proposed > 0 {
        receipt
            .validation_results
            .push("memory candidate gate reviewed".to_string());
    }
    receipt
        .validation_results
        .push(format!("loop_mode={}", loop_mode.as_str()));
    receipt.validation_results.extend(
        receipt
            .matched_stop_conditions
            .iter()
            .map(|condition| format!("stop_condition_met={condition}")),
    );
    receipt.intentional_omissions = vec![
        "Raw user prompt is not stored in the context receipt.".to_string(),
        "Raw tool result bodies are omitted; use evidence refs and excerpts instead.".to_string(),
        "API keys and local secrets are omitted.".to_string(),
        "Full memory bodies are omitted; selected memories use bounded reviewed snippets."
            .to_string(),
    ];
    receipt
        .intentional_omissions
        .extend(memory_context.omissions.iter().cloned());
    if memory_candidate_gate.proposed > 0 {
        receipt.intentional_omissions.push(
            "Rejected memory candidate bodies are omitted; only gate counts and safe kept labels are stored."
                .to_string(),
        );
    }
    receipt
}

fn agent_context_matched_stop_conditions(
    action: &AgentChatActionProposal,
    loop_mode: AgentLoopMode,
) -> Vec<String> {
    if action.execution_state == "blocked" || action.execution_state == "failed" {
        return vec!["blocked_or_failed".to_string()];
    }
    if action.execution_state == "needs_confirmation" || action.requires_confirmation {
        return vec!["user_confirmation_required".to_string()];
    }
    if action.execution_state == "waiting_prerequisite" {
        return vec!["missing_prerequisite".to_string()];
    }
    if action.execution_state != "succeeded" {
        return Vec::new();
    }

    match loop_mode {
        AgentLoopMode::DirectAnswer => vec!["answer_ready".to_string()],
        AgentLoopMode::EvidenceGathering => vec!["evidence_observed".to_string()],
        AgentLoopMode::PermissionedAction => vec!["action_completed".to_string()],
        AgentLoopMode::WorkflowRun => vec!["workflow_draft_ready".to_string()],
        AgentLoopMode::CodingRepair => vec!["tests_passed".to_string()],
        AgentLoopMode::Review => vec!["review_item_queued".to_string()],
        AgentLoopMode::Verification => vec!["verification_passed".to_string()],
        AgentLoopMode::Resume => vec!["resume_ready".to_string()],
    }
}

fn agent_context_policy_constraints(
    action: &AgentChatActionProposal,
    access_mode: &str,
) -> Vec<String> {
    let mut constraints = vec![
        format!("access_mode={access_mode}"),
        format!("requires_confirmation={}", action.requires_confirmation),
    ];
    if let Some(capability) = action.capability.as_ref() {
        constraints.push(format!(
            "capability={}",
            serialize_agent_chat_context_value(capability)
        ));
    }
    if let Some(decision) = action.policy_decision.as_ref() {
        constraints.push(format!(
            "policy_decision={}",
            serialize_agent_chat_context_value(decision)
        ));
    }
    constraints.push(match action.permission_request_id {
        Some(permission_request_id) => format!("permission_request={permission_request_id}"),
        None => "permission_request=none".to_string(),
    });
    if let Some(capability_invocation_id) = action.capability_invocation_id {
        constraints.push(format!("capability_invocation={capability_invocation_id}"));
    }
    if let Some(workflow_run_id) = action.workflow_run_id {
        constraints.push(format!("workflow_run={workflow_run_id}"));
    }
    constraints
}

fn agent_context_selected_evidence(action: &AgentChatActionProposal) -> Vec<String> {
    let mut evidence = Vec::new();
    if let Some(invocation_id) = action.capability_invocation_id {
        evidence.push(format!("capability_invocation:{invocation_id}"));
    }
    if let Some(workflow_run_id) = action.workflow_run_id {
        evidence.push(format!("workflow_run:{workflow_run_id}"));
    }
    if let Some(target) = action
        .target
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        evidence.push(format!(
            "target:{}",
            agent_context_truncate_chars(target, 240)
        ));
    }
    if let Some(note) = action
        .dispatch_note
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        evidence.push(format!(
            "dispatch_note:{}",
            agent_context_truncate_chars(note, 480)
        ));
    }
    evidence
}

fn agent_context_validation_results(action: &AgentChatActionProposal) -> Vec<String> {
    let mut results = vec![
        "model proposal parsed and normalized".to_string(),
        format!("execution_state={}", action.execution_state),
    ];
    if action.capability_invocation_id.is_some() {
        results.push("capability invocation recorded".to_string());
    }
    if let Some(decision) = action.policy_decision {
        results.push(format!(
            "policy_decision={}",
            serialize_agent_chat_context_value(&decision)
        ));
    }
    if let Some(blocked_reason) = action
        .blocked_reason
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        results.push(format!(
            "blocked_reason={}",
            agent_context_truncate_chars(blocked_reason, 240)
        ));
    }
    results
}

fn agent_context_truncate_chars(value: &str, max_chars: usize) -> String {
    let mut output = String::new();
    for (index, character) in value.chars().enumerate() {
        if index >= max_chars {
            output.push_str("[truncated]");
            return output;
        }
        output.push(character);
    }
    output
}

fn apply_agent_local_completion_summary(response: &mut AgentChatResponse) {
    let completed_actions = completed_agent_action_user_summaries(response);
    if completed_actions.is_empty() {
        return;
    }

    response.content = if completed_actions.len() == 1 {
        completed_actions[0].clone()
    } else {
        format!(
            "已完成以下操作：\n{}",
            completed_actions
                .iter()
                .map(|summary| format!("- {summary}"))
                .collect::<Vec<_>>()
                .join("\n")
        )
    };
}

fn completed_agent_action_user_summaries(response: &AgentChatResponse) -> Vec<String> {
    response
        .proposed_actions
        .iter()
        .filter(|action| action.execution_state == "succeeded")
        .map(agent_action_user_summary)
        .collect()
}

fn agent_action_user_summary(action: &AgentChatActionProposal) -> String {
    let target = action
        .target
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty());

    match action.action_type.as_str() {
        "app_update_check" => agent_app_update_check_user_summary(action),
        "app_update_download" => target
            .map(|_| "更新安装包已下载并绑定安全回执。".to_string())
            .unwrap_or_else(|| "更新安装包已下载并验证。".to_string()),
        "app_update_install" => "更新安装程序已启动。完成后 DS Agent 会重新打开。".to_string(),
        "browser_open" => target
            .map(|url| format!("已打开：{url}。"))
            .unwrap_or_else(|| "已打开你指定的网页。".to_string()),
        "connected_mail_review" => {
            "邮件草稿已准备好，正在等待你核对内容并进行最终批准；尚未发送。".to_string()
        }
        "connected_calendar_review" => {
            "日历变更已准备好，正在等待你核对内容并进行最终批准；尚未修改日历。".to_string()
        }
        "skill_install" => agent_skill_install_user_summary(action),
        "skill_create" => agent_skill_create_user_summary(action),
        "skill_uninstall" => agent_skill_uninstall_user_summary(action),
        "office_create" => user_summary_with_target("已创建文件", target),
        "office_update" => user_summary_with_target("已更新文件", target),
        "office_open" => user_summary_with_target("已打开文件", target),
        "file_create" | "file_write" | "create_report" => {
            user_summary_with_target("已保存文件", target)
        }
        "file_update" => user_summary_with_target("已更新文件", target),
        "file_delete" => user_summary_with_target("已删除文件", target),
        "file_rename" => {
            user_summary_with_move("已重命名文件", target, action.destination.as_deref())
        }
        "directory_create" => user_summary_with_target("已创建文件夹", target),
        "directory_delete" => user_summary_with_target("已删除文件夹", target),
        "directory_rename" => {
            user_summary_with_move("已重命名文件夹", target, action.destination.as_deref())
        }
        "file_read" => user_summary_with_target("已读取文件", target),
        "terminal_read" => user_summary_with_target("已读取", target),
        "computer_screenshot" => "已查看当前屏幕。".to_string(),
        "computer_control" => "已完成电脑操作。".to_string(),
        _ => format!(
            "已完成：{}。",
            action
                .title
                .as_deref()
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .unwrap_or("你请求的操作")
        ),
    }
}

fn agent_skill_install_user_summary(action: &AgentChatActionProposal) -> String {
    let output = agent_action_dispatch_output(action);
    let name = output
        .as_ref()
        .and_then(|value| value.pointer("/record/manifest/name"))
        .and_then(serde_json::Value::as_str)
        .unwrap_or("Skill");
    let version = output
        .as_ref()
        .and_then(|value| value.pointer("/record/manifest/version"))
        .and_then(serde_json::Value::as_str);
    let operation = output
        .as_ref()
        .and_then(|value| value.get("operation"))
        .and_then(serde_json::Value::as_str);
    match (operation, version) {
        (Some("updated"), Some(version)) => {
            format!("已自动升级并启用 {name} {version}。")
        }
        (Some("unchanged"), Some(version)) => {
            format!("{name} {version} 已安装并且是最新版。")
        }
        (_, Some(version)) => format!("已自动安装并启用 {name} {version}。"),
        _ => format!("已自动安装并启用 {name}。"),
    }
}

fn agent_skill_create_user_summary(action: &AgentChatActionProposal) -> String {
    let output = agent_action_dispatch_output(action);
    let name = output
        .as_ref()
        .and_then(|value| value.pointer("/manifest/name"))
        .and_then(serde_json::Value::as_str)
        .unwrap_or("新 Skill");
    let version = output
        .as_ref()
        .and_then(|value| value.pointer("/manifest/version"))
        .and_then(serde_json::Value::as_str);
    match version {
        Some(version) => format!("已制作、测试、安装并启用 {name} {version}。"),
        None => format!("已制作、测试、安装并启用 {name}。"),
    }
}

fn agent_skill_uninstall_user_summary(action: &AgentChatActionProposal) -> String {
    let name = agent_action_dispatch_output(action)
        .as_ref()
        .and_then(|value| value.get("name"))
        .and_then(serde_json::Value::as_str)
        .map(str::to_string)
        .or_else(|| action.target.clone())
        .unwrap_or_else(|| "该 Skill".to_string());
    format!("已卸载 {name}，并从自动调用目录中移除。")
}

fn user_summary_with_target(label: &str, target: Option<&str>) -> String {
    target
        .map(|target| format!("{label}：{target}。"))
        .unwrap_or_else(|| format!("{label}。"))
}

fn user_summary_with_move(label: &str, target: Option<&str>, destination: Option<&str>) -> String {
    let destination = destination.map(str::trim).filter(|value| !value.is_empty());
    match (target, destination) {
        (Some(target), Some(destination)) => format!("{label}：{target} → {destination}。"),
        (Some(target), None) => format!("{label}：{target}。"),
        _ => format!("{label}。"),
    }
}

fn agent_app_update_check_user_summary(action: &AgentChatActionProposal) -> String {
    let output = agent_action_dispatch_output(action);
    let current_version = output
        .as_ref()
        .and_then(|value| value.get("current_version"))
        .and_then(serde_json::Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let latest_version = output
        .as_ref()
        .and_then(|value| value.get("latest_version"))
        .and_then(serde_json::Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let update_available = output
        .as_ref()
        .and_then(|value| value.get("update_available"))
        .and_then(serde_json::Value::as_bool);

    match (current_version, latest_version, update_available) {
        (Some(current), _, Some(false)) => {
            format!("已检查 DS Agent 版本。你当前使用的是 {current}，已经是最新版，无需升级。")
        }
        (Some(current), Some(latest), Some(true)) => {
            format!("已检查 DS Agent 版本。当前版本是 {current}，最新版本是 {latest}，可以升级。")
        }
        (Some(current), _, _) => format!("已检查 DS Agent 版本。当前版本是 {current}。"),
        _ => "已完成 DS Agent 版本检查。".to_string(),
    }
}

fn agent_action_dispatch_output(action: &AgentChatActionProposal) -> Option<serde_json::Value> {
    let note = action.dispatch_note.as_deref()?;
    let (_, output) = note.rsplit_once("output=")?;
    serde_json::from_str(output.trim()).ok()
}

fn agent_action_dispatch_summary(action: &AgentChatActionProposal) -> Option<String> {
    let note = action
        .dispatch_note
        .as_deref()
        .map(str::trim)
        .filter(|note| !note.is_empty())?;
    Some(format!(
        "- {} ({}) target={}: {}",
        action
            .title
            .as_deref()
            .unwrap_or(action.action_type.as_str()),
        action.action_type,
        action.target.as_deref().unwrap_or("not specified"),
        note
    ))
}

fn completed_agent_action_dispatch_summaries_for_model(
    response: &AgentChatResponse,
) -> Vec<String> {
    response
        .proposed_actions
        .iter()
        .filter(|action| action.execution_state == "succeeded")
        .filter_map(agent_action_dispatch_summary_for_model)
        .collect()
}

fn agent_action_dispatch_summary_for_model(action: &AgentChatActionProposal) -> Option<String> {
    let summary = agent_action_dispatch_summary(action)?;
    let loop_mode = classify_agent_action_loop_mode(
        &action.action_type,
        &action.execution_state,
        action.requires_confirmation,
        action.workflow_run_id.is_some(),
    );
    let loop_mode_descriptor = agent_loop_mode_descriptor(loop_mode);
    let matched_stop_conditions = agent_context_matched_stop_conditions(action, loop_mode);
    Some(format!(
        "{summary}\n  Loop context: loop_mode={} matched_stop_conditions={} validators={} stop_conditions={}",
        loop_mode.as_str(),
        matched_stop_conditions.join(","),
        loop_mode_descriptor.validators.join(","),
        loop_mode_descriptor.stop_conditions.join(",")
    ))
}

fn agent_action_needs_model_evidence_followup(action: &AgentChatActionProposal) -> bool {
    if action.execution_state != "succeeded" {
        return false;
    }

    matches!(
        action.action_type.as_str(),
        "browser_browse"
            | "computer_screenshot"
            | "create_report"
            | "file_read"
            | "file_write"
            | "network_search"
            | "operations_briefing"
            | "skill_activate"
            | "terminal_read"
    )
}

fn merge_agent_chat_followup_response(
    mut initial_response: AgentChatResponse,
    mut followup_response: AgentChatResponse,
) -> AgentChatResponse {
    if followup_response.goal_envelope.is_none() {
        followup_response.goal_envelope = initial_response.goal_envelope.take();
    }
    if followup_response.goal_projection.is_none() {
        followup_response.goal_projection = initial_response.goal_projection.take();
    }
    if followup_response.task_capability_proposal.is_none() {
        followup_response.task_capability_proposal =
            initial_response.task_capability_proposal.take();
    }
    initial_response
        .proposed_actions
        .append(&mut followup_response.proposed_actions);
    followup_response.proposed_actions = initial_response.proposed_actions;
    initial_response
        .missing_prerequisites
        .append(&mut followup_response.missing_prerequisites);
    followup_response.missing_prerequisites = initial_response.missing_prerequisites;
    followup_response
        .memory_candidates
        .splice(0..0, initial_response.memory_candidates);
    if followup_response.soul_profile_update_proposal.is_none() {
        followup_response.soul_profile_update_proposal =
            initial_response.soul_profile_update_proposal.take();
    }
    followup_response
}

fn agent_chat_completed_actions_followup_failed_message(error: &str) -> String {
    let reason = if error.contains("could not be read")
        || error.contains("decoding response body")
        || error.contains("timed out")
        || error.contains("timeout")
    {
        "DeepSeek 响应读取失败或超时"
    } else {
        "DeepSeek 最终说明生成失败"
    };

    format!(
        "DS Agent 已完成本地动作，但 DeepSeek 最终说明读取失败。请查看右侧运行步骤确认已完成动作；如需重新生成说明，可以稍后重试。（原因：{reason}。）"
    )
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum AgentMemoryCandidateGateDropReason {
    Sensitive,
    Transient,
    Archived,
    Invalid,
    OverLimit,
}

#[derive(Clone, Debug, Default, Eq, PartialEq)]
struct AgentMemoryCandidateGateReceipt {
    proposed: usize,
    kept: usize,
    dropped_sensitive: usize,
    dropped_transient: usize,
    dropped_archived: usize,
    dropped_invalid: usize,
    dropped_over_limit: usize,
    kept_summaries: Vec<String>,
}

impl AgentMemoryCandidateGateReceipt {
    fn dropped(&self) -> usize {
        self.dropped_sensitive
            + self.dropped_transient
            + self.dropped_archived
            + self.dropped_invalid
            + self.dropped_over_limit
    }

    fn record_drop(&mut self, reason: AgentMemoryCandidateGateDropReason) {
        match reason {
            AgentMemoryCandidateGateDropReason::Sensitive => self.dropped_sensitive += 1,
            AgentMemoryCandidateGateDropReason::Transient => self.dropped_transient += 1,
            AgentMemoryCandidateGateDropReason::Archived => self.dropped_archived += 1,
            AgentMemoryCandidateGateDropReason::Invalid => self.dropped_invalid += 1,
            AgentMemoryCandidateGateDropReason::OverLimit => self.dropped_over_limit += 1,
        }
    }

    fn record_kept(&mut self, candidate: &MemoryCandidate) {
        self.kept += 1;
        self.kept_summaries.push(format!(
            "kept title={}; suggested_action={}; privacy_review={}",
            agent_memory_candidate_receipt_value(&candidate.title, 96),
            agent_memory_candidate_suggested_action_label(candidate.suggested_action),
            candidate.privacy_review
        ));
    }
}

fn apply_agent_memory_candidate_gate(
    store: &EventStore,
    response: &mut AgentChatResponse,
) -> Result<AgentMemoryCandidateGateReceipt, String> {
    let memories = store.list_memory_records().map_err(event_store_error)?;
    let (candidates, receipt) =
        gate_agent_memory_candidates_for_review(&response.memory_candidates, &memories);
    response.memory_candidates = candidates;
    Ok(receipt)
}

fn gate_agent_memory_candidates_for_review(
    candidates: &[MemoryCandidate],
    memories: &[MemoryRecord],
) -> (Vec<MemoryCandidate>, AgentMemoryCandidateGateReceipt) {
    let mut receipt = AgentMemoryCandidateGateReceipt {
        proposed: candidates.len(),
        ..AgentMemoryCandidateGateReceipt::default()
    };
    let mut gated_candidates = Vec::new();

    for candidate in candidates {
        if let Some(reason) = agent_memory_candidate_gate_drop_reason(candidate) {
            receipt.record_drop(reason);
            continue;
        }
        if gated_candidates.len() >= AGENT_MEMORY_CANDIDATE_GATE_MAX_RECORDS {
            receipt.record_drop(AgentMemoryCandidateGateDropReason::OverLimit);
            continue;
        }
        if let Some(gated_candidate) = gate_agent_memory_candidate_for_review(candidate, memories) {
            receipt.record_kept(&gated_candidate);
            gated_candidates.push(gated_candidate);
        } else {
            receipt.record_drop(AgentMemoryCandidateGateDropReason::Invalid);
        }
    }

    (gated_candidates, receipt)
}

fn gate_agent_memory_candidate_for_review(
    candidate: &MemoryCandidate,
    memories: &[MemoryRecord],
) -> Option<MemoryCandidate> {
    if !agent_memory_candidate_is_reviewable(candidate) {
        return None;
    }

    let mut candidate = candidate.clone();
    let conflict_count = agent_memory_candidate_gate_conflict_count(&candidate, memories);
    candidate.evidence_excerpt =
        agent_context_truncate_chars(&candidate.body, AGENT_MEMORY_CANDIDATE_EVIDENCE_CHARS);
    candidate.privacy_review = "normal".to_string();
    candidate.suggested_action = if conflict_count > 0 {
        MemoryCandidateSuggestedAction::Merge
    } else {
        MemoryCandidateSuggestedAction::New
    };
    let original_rationale =
        agent_context_truncate_chars(&candidate.rationale, AGENT_MEMORY_CANDIDATE_REASON_CHARS);
    candidate.rationale = format!(
        "Memory Candidate Gate: why_remember={}; privacy_review={}; suggested_action={}; evidence_excerpt={}; conflict_count={}; original_rationale={}",
        agent_memory_candidate_gate_why(&candidate),
        candidate.privacy_review,
        agent_memory_candidate_suggested_action_label(candidate.suggested_action),
        candidate.evidence_excerpt,
        conflict_count,
        original_rationale
    );
    Some(candidate)
}

fn agent_memory_candidate_is_reviewable(candidate: &MemoryCandidate) -> bool {
    agent_memory_candidate_gate_drop_reason(candidate).is_none()
}

fn agent_memory_candidate_gate_drop_reason(
    candidate: &MemoryCandidate,
) -> Option<AgentMemoryCandidateGateDropReason> {
    if candidate.sensitivity == MemorySensitivity::Sensitive
        || agent_memory_candidate_contains_sensitive_text(candidate)
    {
        return Some(AgentMemoryCandidateGateDropReason::Sensitive);
    }
    if agent_memory_candidate_is_transient(candidate) {
        return Some(AgentMemoryCandidateGateDropReason::Transient);
    }
    if candidate.lifecycle == MemoryLifecycle::Archived {
        return Some(AgentMemoryCandidateGateDropReason::Archived);
    }
    if candidate.title.trim().is_empty() || candidate.body.trim().is_empty() {
        return Some(AgentMemoryCandidateGateDropReason::Invalid);
    }
    None
}

fn agent_memory_candidate_gate_receipt_lines(
    receipt: &AgentMemoryCandidateGateReceipt,
) -> Vec<String> {
    if receipt.proposed == 0 {
        return Vec::new();
    }

    let mut lines = vec![format!(
        "proposed={}; kept={}; dropped={}; reasons=sensitive={},transient={},archived={},invalid={},over_limit={}",
        receipt.proposed,
        receipt.kept,
        receipt.dropped(),
        receipt.dropped_sensitive,
        receipt.dropped_transient,
        receipt.dropped_archived,
        receipt.dropped_invalid,
        receipt.dropped_over_limit
    )];
    lines.extend(
        receipt
            .kept_summaries
            .iter()
            .take(AGENT_MEMORY_CANDIDATE_GATE_MAX_RECORDS)
            .cloned(),
    );
    lines
}

fn agent_memory_candidate_receipt_value(value: &str, max_chars: usize) -> String {
    let normalized = value.split_whitespace().collect::<Vec<_>>().join(" ");
    agent_context_truncate_chars(&normalized, max_chars)
}

fn agent_memory_candidate_contains_sensitive_text(candidate: &MemoryCandidate) -> bool {
    let haystack = agent_memory_candidate_gate_haystack(candidate);
    [
        "password",
        "passcode",
        "api key",
        "secret",
        "token",
        "hunter2",
        "sk-",
        "密码",
        "密钥",
        "令牌",
        "身份证",
        "手机号",
        "银行卡",
    ]
    .iter()
    .any(|marker| haystack.contains(marker))
}

fn agent_memory_candidate_is_transient(candidate: &MemoryCandidate) -> bool {
    let haystack = agent_memory_candidate_gate_haystack(candidate);
    [
        "only for today",
        "today's",
        "one-off",
        "temporary",
        "for this task",
        "current task",
        "本次",
        "这次",
        "临时",
        "一次性",
        "今天",
        "只在",
    ]
    .iter()
    .any(|marker| haystack.contains(marker))
}

fn agent_memory_candidate_gate_conflict_count(
    candidate: &MemoryCandidate,
    memories: &[MemoryRecord],
) -> usize {
    memories
        .iter()
        .filter(|memory| {
            memory.sensitivity != MemorySensitivity::Sensitive
                && memory.lifecycle != MemoryLifecycle::Archived
                && agent_memory_candidate_gate_conflicts_with_memory(candidate, memory)
        })
        .count()
}

fn agent_memory_candidate_gate_conflicts_with_memory(
    candidate: &MemoryCandidate,
    memory: &MemoryRecord,
) -> bool {
    let candidate_title = candidate.title.trim().to_lowercase();
    let memory_title = memory.title.trim().to_lowercase();
    if !candidate_title.is_empty() && candidate_title == memory_title {
        return true;
    }

    let candidate_body = candidate.body.trim().to_lowercase();
    let memory_body = memory.body.trim().to_lowercase();
    !candidate_body.is_empty()
        && !memory_body.is_empty()
        && (candidate_body.contains(&memory_body) || memory_body.contains(&candidate_body))
}

fn agent_memory_candidate_gate_haystack(candidate: &MemoryCandidate) -> String {
    format!(
        "{}\n{}\n{}",
        candidate.title, candidate.body, candidate.rationale
    )
    .to_lowercase()
}

fn agent_memory_candidate_gate_why(candidate: &MemoryCandidate) -> &'static str {
    match candidate.memory_type {
        MemoryType::Preference => "stable_user_preference",
        MemoryType::ProjectContext => "project_context",
        MemoryType::WorkflowRule => "workflow_rule",
        MemoryType::Artifact => "artifact_reference",
        MemoryType::FailurePattern => "failure_pattern",
    }
}

fn agent_memory_candidate_suggested_action_label(
    action: MemoryCandidateSuggestedAction,
) -> &'static str {
    match action {
        MemoryCandidateSuggestedAction::New => "new",
        MemoryCandidateSuggestedAction::Update => "update",
        MemoryCandidateSuggestedAction::Merge => "merge",
        MemoryCandidateSuggestedAction::Replace => "replace",
        MemoryCandidateSuggestedAction::Archive => "archive",
        MemoryCandidateSuggestedAction::Link => "link",
        MemoryCandidateSuggestedAction::RejectHint => "reject_hint",
    }
}

fn record_agent_memory_candidates(
    store: &EventStore,
    response: &AgentChatResponse,
) -> Result<(), String> {
    for candidate in &response.memory_candidates {
        store
            .append_memory_candidate(candidate)
            .map_err(event_store_error)?;
    }
    Ok(())
}

fn record_agent_action_permission_requests(
    store: &EventStore,
    access_mode: AccessMode,
    response: &mut AgentChatResponse,
) -> Result<(), String> {
    for action in &mut response.proposed_actions {
        let Some(capability) = action.capability else {
            continue;
        };
        if action.policy_decision != Some(PolicyDecision::Ask) {
            continue;
        }
        if action.permission_request_id.is_some() {
            continue;
        }

        let request = build_capability_access_request(access_mode, capability)?;
        let entry = PermissionAuditEntry::evaluate(access_mode, capability);
        store
            .append_capability_access_request(&request)
            .map_err(event_store_error)?;
        store
            .append_permission_audit_entry(&entry)
            .map_err(event_store_error)?;

        action.permission_request_id = Some(request.id);
        action.dispatch_note =
            Some("waiting for local permission approval before dispatch".to_string());
    }

    Ok(())
}

fn skill_install_source_url(action: &AgentChatActionProposal) -> Result<String, String> {
    [action.target.as_deref(), action.content.as_deref()]
        .into_iter()
        .flatten()
        .find_map(extract_safe_browser_url)
        .filter(|url| SkillRepositorySource::parse(url).is_ok())
        .ok_or_else(|| {
            "skill_install requires an exact GitHub or Hugging Face repository URL".to_string()
        })
}

fn apply_skill_install_result(
    action: &mut AgentChatActionProposal,
    source_url: String,
    result: Result<SkillRepositoryInstallResult, String>,
) {
    action.target = Some(source_url);
    action.requires_confirmation = false;
    match result {
        Ok(result) => {
            action.execution_state = "succeeded".to_string();
            action.blocked_reason = None;
            action.dispatch_note = Some(format!(
                "repository Skill lifecycle completed automatically; output={}",
                serde_json::to_string(&result).unwrap_or_else(|_| "{}".to_string())
            ));
        }
        Err(error) => {
            action.execution_state = "failed".to_string();
            action.blocked_reason = Some(error.clone());
            action.dispatch_note = Some(format!(
                "repository Skill lifecycle failed without changing the installed catalog: {error}"
            ));
        }
    }
}

fn dispatch_agent_skill_install_action(store: &EventStore, action: &mut AgentChatActionProposal) {
    let source_url = match skill_install_source_url(action) {
        Ok(source_url) => source_url,
        Err(error) => {
            apply_skill_install_result(action, String::new(), Err(error));
            return;
        }
    };
    let result = SkillRepositorySource::parse(&source_url).and_then(|source| {
        fetch_repository_skill_installation(&source_url)
            .and_then(|candidate| commit_repository_skill_installation(store, &source, candidate))
    });
    apply_skill_install_result(action, source_url, result);
}

fn dispatch_agent_skill_install_action_with_store_mutex(
    store_mutex: &Mutex<EventStore>,
    action: &mut AgentChatActionProposal,
) {
    let source_url = match skill_install_source_url(action) {
        Ok(source_url) => source_url,
        Err(error) => {
            apply_skill_install_result(action, String::new(), Err(error));
            return;
        }
    };
    let result = SkillRepositorySource::parse(&source_url).and_then(|source| {
        fetch_repository_skill_installation(&source_url).and_then(|candidate| {
            let store = store_mutex.lock().map_err(|_| lock_error())?;
            commit_repository_skill_installation(&store, &source, candidate)
        })
    });
    apply_skill_install_result(action, source_url, result);
}

fn generated_skill_request_from_action(
    action: &AgentChatActionProposal,
) -> Result<GeneratedSkillRequest, String> {
    let content = action
        .content
        .as_deref()
        .map(str::trim)
        .filter(|content| !content.is_empty())
        .ok_or_else(|| "skill_create requires declarative instructions".to_string())?;
    if let Ok(mut request) = serde_json::from_str::<GeneratedSkillRequest>(content) {
        if request.name.trim().is_empty() {
            request.name = action.target.clone().unwrap_or_default();
        }
        return Ok(request);
    }
    Ok(GeneratedSkillRequest {
        name: action
            .target
            .clone()
            .or_else(|| action.title.clone())
            .unwrap_or_default(),
        description: action
            .reason
            .clone()
            .or_else(|| action.title.clone())
            .unwrap_or_else(|| "User-requested DS Agent Skill.".to_string()),
        instructions: content.to_string(),
        kind: "skill".to_string(),
    })
}

fn apply_skill_create_result(
    action: &mut AgentChatActionProposal,
    result: Result<SkillRecord, String>,
) {
    action.requires_confirmation = false;
    match result {
        Ok(record) => {
            action.target = Some(record.manifest.name.clone());
            action.execution_state = "succeeded".to_string();
            action.blocked_reason = None;
            action.dispatch_note = Some(format!(
                "generated Skill validated, activation-tested, installed, and enabled; output={}",
                serde_json::to_string(&record).unwrap_or_else(|_| "{}".to_string())
            ));
        }
        Err(error) => {
            action.execution_state = "failed".to_string();
            action.blocked_reason = Some(error.clone());
            action.dispatch_note = Some(format!(
                "generated Skill was rejected before activation: {error}"
            ));
        }
    }
}

fn dispatch_agent_skill_create_action(store: &EventStore, action: &mut AgentChatActionProposal) {
    let result = generated_skill_request_from_action(action)
        .and_then(|request| create_generated_skill_with_store(store, request));
    apply_skill_create_result(action, result);
}

fn dispatch_agent_skill_create_action_with_store_mutex(
    store_mutex: &Mutex<EventStore>,
    action: &mut AgentChatActionProposal,
) {
    let result = generated_skill_request_from_action(action).and_then(|request| {
        let store = store_mutex.lock().map_err(|_| lock_error())?;
        create_generated_skill_with_store(&store, request)
    });
    apply_skill_create_result(action, result);
}

fn uninstall_skill_from_action(
    store: &EventStore,
    action: &AgentChatActionProposal,
) -> Result<serde_json::Value, String> {
    let target = action
        .target
        .as_deref()
        .map(str::trim)
        .filter(|target| !target.is_empty())
        .ok_or_else(|| {
            "skill_uninstall requires an installed Skill id or exact name".to_string()
        })?;
    let target_id = Uuid::parse_str(target).ok();
    let record = store
        .list_skill_records()
        .map_err(event_store_error)?
        .into_iter()
        .find(|record| {
            Some(record.id) == target_id || record.manifest.name.eq_ignore_ascii_case(target)
        })
        .ok_or_else(|| format!("installed Skill was not found: {target}"))?;
    let uninstall = SkillUninstallRecord::new(
        record.id,
        "Removed automatically from an explicit user request.".to_string(),
    )
    .map_err(event_store_error)?;
    store
        .append_skill_uninstall(&uninstall)
        .map_err(event_store_error)?;
    Ok(serde_json::json!({
        "id": record.id,
        "name": record.manifest.name,
        "uninstalled": true
    }))
}

fn apply_skill_uninstall_result(
    action: &mut AgentChatActionProposal,
    result: Result<serde_json::Value, String>,
) {
    action.requires_confirmation = false;
    match result {
        Ok(output) => {
            action.execution_state = "succeeded".to_string();
            action.blocked_reason = None;
            action.dispatch_note = Some(format!(
                "installed Skill removed from the runtime catalog; output={output}"
            ));
        }
        Err(error) => {
            action.execution_state = "failed".to_string();
            action.blocked_reason = Some(error.clone());
            action.dispatch_note = Some(format!("Skill uninstall kept the prior state: {error}"));
        }
    }
}

fn dispatch_agent_skill_uninstall_action(store: &EventStore, action: &mut AgentChatActionProposal) {
    let result = uninstall_skill_from_action(store, action);
    apply_skill_uninstall_result(action, result);
}

fn dispatch_agent_skill_uninstall_action_with_store_mutex(
    store_mutex: &Mutex<EventStore>,
    action: &mut AgentChatActionProposal,
) {
    let result = store_mutex
        .lock()
        .map_err(|_| lock_error())
        .and_then(|store| uninstall_skill_from_action(&store, action));
    apply_skill_uninstall_result(action, result);
}

fn dispatch_agent_action_proposals(
    store: &EventStore,
    access_mode: AccessMode,
    response: &mut AgentChatResponse,
    file_client: &impl FileContentClient,
    file_write_client: &impl AgentWritableArtifactClient,
    search_client: &impl NetworkSearchClient,
    browser_client: &impl BrowserPageClient,
) -> Result<(), String> {
    dispatch_agent_action_proposals_with_desktop_dir_and_computer_use(
        store,
        access_mode,
        response,
        file_client,
        file_write_client,
        search_client,
        browser_client,
        &UnavailableAgentComputerUseClient,
        None,
    )
}

fn dispatch_agent_action_proposals_with_desktop_dir(
    store: &EventStore,
    access_mode: AccessMode,
    response: &mut AgentChatResponse,
    file_client: &impl FileContentClient,
    file_write_client: &impl AgentWritableArtifactClient,
    search_client: &impl NetworkSearchClient,
    browser_client: &impl BrowserPageClient,
    desktop_dir: Option<&Path>,
) -> Result<(), String> {
    dispatch_agent_action_proposals_with_desktop_dir_and_computer_use(
        store,
        access_mode,
        response,
        file_client,
        file_write_client,
        search_client,
        browser_client,
        &UnavailableAgentComputerUseClient,
        desktop_dir,
    )
}

fn dispatch_agent_action_proposals_with_desktop_dir_and_computer_use(
    store: &EventStore,
    access_mode: AccessMode,
    response: &mut AgentChatResponse,
    file_client: &impl FileContentClient,
    file_write_client: &impl AgentWritableArtifactClient,
    search_client: &impl NetworkSearchClient,
    browser_client: &impl BrowserPageClient,
    computer_use_client: &(impl ComputerScreenshotClient + ComputerControlClient),
    desktop_dir: Option<&Path>,
) -> Result<(), String> {
    if !response.missing_prerequisites.is_empty() {
        mark_agent_actions_waiting_for_prerequisites(response);
        return Ok(());
    }
    mark_office_open_actions_waiting_for_pending_create(response);
    let response_id = response.id;

    for action in &mut response.proposed_actions {
        if action.execution_state == "blocked" {
            continue;
        }

        if matches!(
            action.execution_state.as_str(),
            "waiting_prerequisite" | "succeeded" | "failed"
        ) {
            continue;
        }

        if is_connected_work_agent_action(&action.action_type) {
            let source_run_id = agent_tool_run_id_for_action(store, action)?.or(Some(response_id));
            dispatch_connected_work_agent_action(store, action, source_run_id)?;
            continue;
        }

        if is_agent_app_update_action(&action.action_type) {
            if action.action_type == "app_update_install" {
                action.execution_state = "needs_confirmation".to_string();
                action.dispatch_note = Some(
                    "verified installer execution must resume from the local approval card"
                        .to_string(),
                );
            } else {
                dispatch_agent_app_update_action_with_executor(
                    store,
                    access_mode,
                    action,
                    &BuiltinAgentToolExecutor,
                )?;
            }
            continue;
        }

        if action.action_type == "skill_install" {
            dispatch_agent_skill_install_action(store, action);
            continue;
        }

        if action.action_type == "skill_create" {
            dispatch_agent_skill_create_action(store, action);
            continue;
        }

        if action.action_type == "skill_uninstall" {
            dispatch_agent_skill_uninstall_action(store, action);
            continue;
        }

        if action.action_type == "skill_activate" {
            let run_id = agent_tool_run_id_for_action(store, action)?;
            let invocation = dispatch_agent_skill_activate_tool_with_executor(
                store,
                access_mode,
                action,
                run_id,
            )?;
            finish_agent_run_after_resumed_tool(store, &invocation)?;
            continue;
        }

        if action.action_type == "office_create" {
            let run_id = agent_tool_run_id_for_action(store, action)?;
            let invocation = dispatch_agent_office_create_tool_with_executor(
                store,
                access_mode,
                action,
                run_id,
                file_write_client,
            )?;
            finish_agent_run_after_resumed_tool(store, &invocation)?;
            continue;
        }

        if action.action_type == "office_update" {
            let run_id = agent_tool_run_id_for_action(store, action)?;
            let invocation = dispatch_agent_office_update_tool_with_executor(
                store,
                access_mode,
                action,
                run_id,
                file_write_client,
            )?;
            finish_agent_run_after_resumed_tool(store, &invocation)?;
            continue;
        }

        if action.action_type == "office_open" {
            let run_id = agent_tool_run_id_for_action(store, action)?;
            let invocation = dispatch_agent_office_open_tool_with_executor(
                store,
                access_mode,
                action,
                run_id,
                file_write_client,
            )?;
            finish_agent_run_after_resumed_tool(store, &invocation)?;
            continue;
        }

        if action.action_type == "browser_open" {
            let run_id = agent_tool_run_id_for_action(store, action)?;
            let invocation = dispatch_agent_browser_open_tool_with_executor(
                store,
                access_mode,
                action,
                run_id,
                &SystemBrowserUrlOpener,
            )?;
            finish_agent_run_after_resumed_tool(store, &invocation)?;
            continue;
        }

        if action.action_type == "operations_briefing" {
            let run_id = agent_tool_run_id_for_action(store, action)?;
            let client = LocalEvidenceFolderClient::new(20, 512 * 1024);
            let invocation = dispatch_agent_operations_briefing_tool_with_executor(
                store,
                access_mode,
                action,
                run_id,
                &client,
            )?;
            finish_agent_run_after_resumed_tool(store, &invocation)?;
            continue;
        }

        let approval_state = agent_action_approval_state(store, action)?;

        if action.action_type == "file_read" {
            match approval_state {
                AgentActionApprovalState::Rejected => {
                    block_agent_tool_action_after_approval_resolution(
                        store,
                        action,
                        "local permission request was rejected before file read dispatch",
                        "local permission was rejected; file read tool was not executed",
                    )?;
                }
                AgentActionApprovalState::Unavailable => {
                    block_agent_tool_action_after_approval_resolution(
                        store,
                        action,
                        "approved local permission is no longer available",
                        "permission grant is unavailable; file read tool was not executed",
                    )?;
                }
                _ => {
                    let run_id = agent_tool_run_id_for_action(store, action)?;
                    let invocation = dispatch_agent_file_read_tool_with_executor(
                        store,
                        access_mode,
                        action,
                        run_id,
                        file_client,
                    )?;
                    finish_agent_run_after_resumed_tool(store, &invocation)?;
                }
            }
            continue;
        }

        if is_agent_file_write_tool_action(&action.action_type) {
            match approval_state {
                AgentActionApprovalState::Rejected => {
                    block_agent_tool_action_after_approval_resolution(
                        store,
                        action,
                        "local permission request was rejected before file write dispatch",
                        "local permission was rejected; file write tool was not executed",
                    )?;
                }
                AgentActionApprovalState::Unavailable => {
                    block_agent_tool_action_after_approval_resolution(
                        store,
                        action,
                        "approved local permission is no longer available",
                        "permission grant is unavailable; file write tool was not executed",
                    )?;
                }
                _ => {
                    let run_id = agent_tool_run_id_for_action(store, action)?;
                    let invocation = dispatch_agent_file_write_tool_with_executor(
                        store,
                        access_mode,
                        action,
                        run_id,
                        file_write_client,
                    )?;
                    finish_agent_run_after_resumed_tool(store, &invocation)?;
                }
            }
            continue;
        }

        if is_agent_filesystem_mutation_action(&action.action_type) {
            match approval_state {
                AgentActionApprovalState::Rejected => {
                    block_agent_tool_action_after_approval_resolution(
                        store,
                        action,
                        "local permission request was rejected before filesystem mutation dispatch",
                        "local permission was rejected; filesystem mutation tool was not executed",
                    )?;
                }
                AgentActionApprovalState::Unavailable => {
                    block_agent_tool_action_after_approval_resolution(
                        store,
                        action,
                        "approved local permission is no longer available",
                        "permission grant is unavailable; filesystem mutation tool was not executed",
                    )?;
                }
                _ => {
                    let run_id = agent_tool_run_id_for_action(store, action)?;
                    let client = LocalFileSystemMutationClient;
                    let invocation = dispatch_agent_filesystem_mutation_tool_with_executor(
                        store,
                        access_mode,
                        action,
                        run_id,
                        &client,
                    )?;
                    finish_agent_run_after_resumed_tool(store, &invocation)?;
                }
            }
            continue;
        }

        if action.action_type == "terminal_read" {
            match approval_state {
                AgentActionApprovalState::Rejected => {
                    block_agent_tool_action_after_approval_resolution(
                        store,
                        action,
                        "local permission request was rejected before terminal read dispatch",
                        "local permission was rejected; terminal read tool was not executed",
                    )?;
                }
                AgentActionApprovalState::Unavailable => {
                    block_agent_tool_action_after_approval_resolution(
                        store,
                        action,
                        "approved local permission is no longer available",
                        "permission grant is unavailable; terminal read tool was not executed",
                    )?;
                }
                _ => {
                    let run_id = agent_tool_run_id_for_action(store, action)?;
                    let client = agent_terminal_read_client()?;
                    let invocation = dispatch_agent_terminal_read_tool_with_executor(
                        store,
                        access_mode,
                        action,
                        run_id,
                        desktop_dir,
                        &client,
                    )?;
                    finish_agent_run_after_resumed_tool(store, &invocation)?;
                }
            }
            continue;
        }

        if action.action_type == "network_search" {
            match approval_state {
                AgentActionApprovalState::Rejected => {
                    block_agent_tool_action_after_approval_resolution(
                        store,
                        action,
                        "local permission request was rejected before network search dispatch",
                        "local permission was rejected; network search tool was not executed",
                    )?;
                }
                AgentActionApprovalState::Unavailable => {
                    block_agent_tool_action_after_approval_resolution(
                        store,
                        action,
                        "approved local permission is no longer available",
                        "permission grant is unavailable; network search tool was not executed",
                    )?;
                }
                _ => {
                    let run_id = agent_tool_run_id_for_action(store, action)?;
                    let invocation = dispatch_agent_network_search_tool_with_executor(
                        store,
                        access_mode,
                        action,
                        run_id,
                        search_client,
                    )?;
                    finish_agent_run_after_resumed_tool(store, &invocation)?;
                }
            }
            continue;
        }

        if action.action_type == "browser_browse" {
            match approval_state {
                AgentActionApprovalState::Rejected => {
                    block_agent_tool_action_after_approval_resolution(
                        store,
                        action,
                        "local permission request was rejected before browser browse dispatch",
                        "local permission was rejected; browser browse tool was not executed",
                    )?;
                }
                AgentActionApprovalState::Unavailable => {
                    block_agent_tool_action_after_approval_resolution(
                        store,
                        action,
                        "approved local permission is no longer available",
                        "permission grant is unavailable; browser browse tool was not executed",
                    )?;
                }
                _ => {
                    let run_id = agent_tool_run_id_for_action(store, action)?;
                    let invocation = dispatch_agent_browser_browse_tool_with_executor(
                        store,
                        access_mode,
                        action,
                        run_id,
                        browser_client,
                    )?;
                    finish_agent_run_after_resumed_tool(store, &invocation)?;
                }
            }
            continue;
        }

        if action.action_type == "computer_screenshot" {
            match approval_state {
                AgentActionApprovalState::Rejected => {
                    block_agent_tool_action_after_approval_resolution(
                        store,
                        action,
                        "local permission request was rejected before screen inspection",
                        "local permission was rejected; screenshot tool was not executed",
                    )?;
                }
                AgentActionApprovalState::Unavailable => {
                    block_agent_tool_action_after_approval_resolution(
                        store,
                        action,
                        "approved local permission is no longer available",
                        "permission grant is unavailable; screenshot tool was not executed",
                    )?;
                }
                _ => {
                    let run_id = agent_tool_run_id_for_action(store, action)?;
                    let invocation = dispatch_agent_computer_screenshot_tool_with_executor(
                        store,
                        access_mode,
                        action,
                        run_id,
                        computer_use_client,
                    )?;
                    finish_agent_run_after_resumed_tool(store, &invocation)?;
                }
            }
            continue;
        }

        if action.action_type == "computer_control" {
            match approval_state {
                AgentActionApprovalState::Rejected => {
                    block_agent_tool_action_after_approval_resolution(
                        store,
                        action,
                        "local permission request was rejected before computer control dispatch",
                        "local permission was rejected; computer control tool was not executed",
                    )?;
                }
                AgentActionApprovalState::Unavailable => {
                    block_agent_tool_action_after_approval_resolution(
                        store,
                        action,
                        "approved local permission is no longer available",
                        "permission grant is unavailable; computer control tool was not executed",
                    )?;
                }
                _ => {
                    let run_id = agent_tool_run_id_for_action(store, action)?;
                    let invocation = dispatch_agent_computer_control_tool_with_executor(
                        store,
                        access_mode,
                        action,
                        run_id,
                        computer_use_client,
                    )?;
                    finish_agent_run_after_resumed_tool(store, &invocation)?;
                }
            }
            continue;
        }

        if action.action_type == "operations_briefing" {
            match approval_state {
                AgentActionApprovalState::Approved(approval_request_id) => {
                    dispatch_agent_operations_briefing_action(
                        store,
                        access_mode,
                        action,
                        true,
                        Some(approval_request_id),
                    )?;
                }
                AgentActionApprovalState::Rejected => {
                    action.execution_state = "blocked".to_string();
                    action.blocked_reason =
                        Some("local permission request was rejected before dispatch".to_string());
                    action.dispatch_note =
                        Some("local permission was rejected; action was not executed".to_string());
                }
                AgentActionApprovalState::Unavailable => {
                    action.execution_state = "blocked".to_string();
                    action.blocked_reason =
                        Some("approved local permission is no longer available".to_string());
                    action.dispatch_note = Some(
                        "permission grant is unavailable; action was not executed".to_string(),
                    );
                }
                _ if action.execution_state == "proposed" => {
                    dispatch_agent_operations_briefing_action(
                        store,
                        access_mode,
                        action,
                        false,
                        None,
                    )?;
                }
                _ => {}
            }
            continue;
        }

        match (action.capability, action.policy_decision, approval_state) {
            (Some(_), Some(PolicyDecision::Ask), AgentActionApprovalState::Rejected) => {
                action.execution_state = "blocked".to_string();
                action.blocked_reason =
                    Some("local permission request was rejected before dispatch".to_string());
                action.dispatch_note =
                    Some("local permission was rejected; action was not executed".to_string());
            }
            (Some(_), Some(PolicyDecision::Ask), AgentActionApprovalState::Unavailable) => {
                action.execution_state = "blocked".to_string();
                action.blocked_reason =
                    Some("approved local permission is no longer available".to_string());
                action.dispatch_note =
                    Some("permission grant is unavailable; action was not executed".to_string());
            }
            (
                Some(CapabilityKind::FileRead),
                Some(PolicyDecision::Ask),
                AgentActionApprovalState::Approved(approval_request_id),
            ) => {
                if action.action_type == "office_open" {
                    dispatch_agent_office_open_action(
                        store,
                        access_mode,
                        action,
                        file_write_client,
                        true,
                        Some(approval_request_id),
                    )?;
                } else {
                    action.execution_state = "blocked".to_string();
                    action.blocked_reason = Some(
                        "file read action has no registered generic tool contract".to_string(),
                    );
                    action.dispatch_note = action.blocked_reason.clone();
                }
            }
            (
                Some(CapabilityKind::FileWrite),
                Some(PolicyDecision::Ask),
                AgentActionApprovalState::Approved(approval_request_id),
            ) => {
                if action.action_type == "office_create" {
                    dispatch_agent_office_create_tool_with_executor(
                        store,
                        access_mode,
                        action,
                        None,
                        file_write_client,
                    )?;
                } else if action.action_type == "office_update" {
                    dispatch_agent_office_update_action(
                        store,
                        access_mode,
                        action,
                        file_write_client,
                        true,
                        Some(approval_request_id),
                    )?;
                } else {
                    action.execution_state = "blocked".to_string();
                    action.blocked_reason = Some(
                        "file write action has no registered generic tool contract".to_string(),
                    );
                    action.dispatch_note = action.blocked_reason.clone();
                }
            }
            (
                Some(CapabilityKind::NetworkSearch),
                Some(PolicyDecision::Ask),
                AgentActionApprovalState::Approved(_),
            ) => {
                action.execution_state = "blocked".to_string();
                action.blocked_reason = Some(
                    "network search action has no registered generic tool contract".to_string(),
                );
                action.dispatch_note = action.blocked_reason.clone();
            }
            (
                Some(CapabilityKind::BrowserBrowse),
                Some(PolicyDecision::Ask),
                AgentActionApprovalState::Approved(approval_request_id),
            ) => {
                if action.action_type == "browser_open" {
                    dispatch_agent_browser_open_action(
                        store,
                        access_mode,
                        action,
                        true,
                        Some(approval_request_id),
                    )?;
                } else {
                    action.execution_state = "blocked".to_string();
                    action.blocked_reason = Some(
                        "browser browse action has no registered generic tool contract".to_string(),
                    );
                    action.dispatch_note = action.blocked_reason.clone();
                }
            }
            (Some(_), Some(PolicyDecision::Ask), AgentActionApprovalState::Approved(_)) => {
                action.dispatch_note =
                    Some("local permission is approved; executor wiring is pending".to_string());
            }
            (Some(_), Some(PolicyDecision::Ask), _) => {
                record_agent_action_permission_request(store, access_mode, action)?;
            }
            (Some(CapabilityKind::FileRead), Some(PolicyDecision::Allow), _) => {
                if action.action_type == "office_open" {
                    dispatch_agent_office_open_action(
                        store,
                        access_mode,
                        action,
                        file_write_client,
                        false,
                        None,
                    )?;
                } else {
                    action.execution_state = "blocked".to_string();
                    action.blocked_reason = Some(
                        "file read action has no registered generic tool contract".to_string(),
                    );
                    action.dispatch_note = action.blocked_reason.clone();
                }
            }
            (Some(CapabilityKind::FileWrite), Some(PolicyDecision::Allow), _) => {
                if action.action_type == "office_create" {
                    dispatch_agent_office_create_tool_with_executor(
                        store,
                        access_mode,
                        action,
                        None,
                        file_write_client,
                    )?;
                } else if action.action_type == "office_update" {
                    dispatch_agent_office_update_action(
                        store,
                        access_mode,
                        action,
                        file_write_client,
                        false,
                        None,
                    )?;
                } else {
                    action.execution_state = "blocked".to_string();
                    action.blocked_reason = Some(
                        "file write action has no registered generic tool contract".to_string(),
                    );
                    action.dispatch_note = action.blocked_reason.clone();
                }
            }
            (Some(CapabilityKind::NetworkSearch), Some(PolicyDecision::Allow), _) => {
                action.execution_state = "blocked".to_string();
                action.blocked_reason = Some(
                    "network search action has no registered generic tool contract".to_string(),
                );
                action.dispatch_note = action.blocked_reason.clone();
            }
            (Some(CapabilityKind::BrowserBrowse), Some(PolicyDecision::Allow), _) => {
                if action.action_type == "browser_open" {
                    dispatch_agent_browser_open_action(store, access_mode, action, false, None)?;
                } else {
                    action.execution_state = "blocked".to_string();
                    action.blocked_reason = Some(
                        "browser browse action has no registered generic tool contract".to_string(),
                    );
                    action.dispatch_note = action.blocked_reason.clone();
                }
            }
            (Some(_), Some(PolicyDecision::Allow), _) => {
                action.dispatch_note = Some(
                    "local capability policy allowed this proposal; executor wiring is pending"
                        .to_string(),
                );
            }
            _ => {}
        }
    }

    Ok(())
}

fn dispatch_agent_action_proposals_with_store_mutex(
    store_mutex: &Mutex<EventStore>,
    access_mode: AccessMode,
    response: &mut AgentChatResponse,
    file_client: &impl FileContentClient,
    file_write_client: &impl AgentWritableArtifactClient,
    search_client: &impl NetworkSearchClient,
    browser_client: &impl BrowserPageClient,
    computer_use_client: &(impl ComputerScreenshotClient + ComputerControlClient),
    desktop_dir: Option<&Path>,
    active_run_id: Option<Uuid>,
) -> Result<(), String> {
    if !response.missing_prerequisites.is_empty() {
        mark_agent_actions_waiting_for_prerequisites(response);
        return Ok(());
    }
    mark_office_open_actions_waiting_for_pending_create(response);
    let response_id = response.id;

    for action in &mut response.proposed_actions {
        if action.execution_state == "blocked" {
            continue;
        }

        if matches!(
            action.execution_state.as_str(),
            "waiting_prerequisite" | "succeeded" | "failed"
        ) {
            continue;
        }

        if is_connected_work_agent_action(&action.action_type) {
            let store = store_mutex.lock().map_err(|_| lock_error())?;
            dispatch_connected_work_agent_action(
                &store,
                action,
                active_run_id.or(Some(response_id)),
            )?;
            continue;
        }

        if is_agent_app_update_action(&action.action_type) {
            dispatch_agent_app_update_action_with_store_mutex(
                store_mutex,
                access_mode,
                action,
                active_run_id,
                &BuiltinAgentToolExecutor,
            )?;
            continue;
        }

        if action.action_type == "skill_install" {
            dispatch_agent_skill_install_action_with_store_mutex(store_mutex, action);
            continue;
        }

        if action.action_type == "skill_create" {
            dispatch_agent_skill_create_action_with_store_mutex(store_mutex, action);
            continue;
        }

        if action.action_type == "skill_uninstall" {
            dispatch_agent_skill_uninstall_action_with_store_mutex(store_mutex, action);
            continue;
        }

        if action.action_type == "skill_activate" {
            dispatch_agent_skill_activate_tool_with_store_mutex(
                store_mutex,
                access_mode,
                action,
                active_run_id,
            )?;
            continue;
        }

        if action.action_type == "office_create" {
            dispatch_agent_office_create_tool_with_store_mutex(
                store_mutex,
                access_mode,
                action,
                active_run_id,
                file_write_client,
            )?;
            continue;
        }

        if action.action_type == "office_update" {
            dispatch_agent_office_update_tool_with_store_mutex(
                store_mutex,
                access_mode,
                action,
                active_run_id,
                file_write_client,
            )?;
            continue;
        }

        if action.action_type == "office_open" {
            dispatch_agent_office_open_tool_with_store_mutex(
                store_mutex,
                access_mode,
                action,
                active_run_id,
                file_write_client,
            )?;
            continue;
        }

        if action.action_type == "browser_open" {
            dispatch_agent_browser_open_tool_with_store_mutex(
                store_mutex,
                access_mode,
                action,
                active_run_id,
                &SystemBrowserUrlOpener,
            )?;
            continue;
        }

        if action.action_type == "operations_briefing" {
            let client = LocalEvidenceFolderClient::new(20, 512 * 1024);
            dispatch_agent_operations_briefing_tool_with_store_mutex(
                store_mutex,
                access_mode,
                action,
                active_run_id,
                &client,
            )?;
            continue;
        }

        let approval_state = {
            let store = store_mutex.lock().map_err(|_| lock_error())?;
            agent_action_approval_state(&store, action)?
        };

        if action.action_type == "file_read" {
            match approval_state {
                AgentActionApprovalState::Rejected => {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    block_agent_tool_action_after_approval_resolution(
                        &store,
                        action,
                        "local permission request was rejected before file read dispatch",
                        "local permission was rejected; file read tool was not executed",
                    )?;
                }
                AgentActionApprovalState::Unavailable => {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    block_agent_tool_action_after_approval_resolution(
                        &store,
                        action,
                        "approved local permission is no longer available",
                        "permission grant is unavailable; file read tool was not executed",
                    )?;
                }
                _ => {
                    dispatch_agent_file_read_tool_with_store_mutex(
                        store_mutex,
                        access_mode,
                        action,
                        active_run_id,
                        file_client,
                    )?;
                }
            }
            continue;
        }

        if is_agent_file_write_tool_action(&action.action_type) {
            match approval_state {
                AgentActionApprovalState::Rejected => {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    block_agent_tool_action_after_approval_resolution(
                        &store,
                        action,
                        "local permission request was rejected before file write dispatch",
                        "local permission was rejected; file write tool was not executed",
                    )?;
                }
                AgentActionApprovalState::Unavailable => {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    block_agent_tool_action_after_approval_resolution(
                        &store,
                        action,
                        "approved local permission is no longer available",
                        "permission grant is unavailable; file write tool was not executed",
                    )?;
                }
                _ => {
                    dispatch_agent_file_write_tool_with_store_mutex(
                        store_mutex,
                        access_mode,
                        action,
                        active_run_id,
                        file_write_client,
                    )?;
                }
            }
            continue;
        }

        if is_agent_filesystem_mutation_action(&action.action_type) {
            match approval_state {
                AgentActionApprovalState::Rejected => {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    block_agent_tool_action_after_approval_resolution(
                        &store,
                        action,
                        "local permission request was rejected before filesystem mutation dispatch",
                        "local permission was rejected; filesystem mutation tool was not executed",
                    )?;
                }
                AgentActionApprovalState::Unavailable => {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    block_agent_tool_action_after_approval_resolution(
                        &store,
                        action,
                        "approved local permission is no longer available",
                        "permission grant is unavailable; filesystem mutation tool was not executed",
                    )?;
                }
                _ => {
                    let client = LocalFileSystemMutationClient;
                    dispatch_agent_filesystem_mutation_tool_with_store_mutex(
                        store_mutex,
                        access_mode,
                        action,
                        active_run_id,
                        &client,
                    )?;
                }
            }
            continue;
        }

        if action.action_type == "terminal_read" {
            match approval_state {
                AgentActionApprovalState::Rejected => {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    block_agent_tool_action_after_approval_resolution(
                        &store,
                        action,
                        "local permission request was rejected before terminal read dispatch",
                        "local permission was rejected; terminal read tool was not executed",
                    )?;
                }
                AgentActionApprovalState::Unavailable => {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    block_agent_tool_action_after_approval_resolution(
                        &store,
                        action,
                        "approved local permission is no longer available",
                        "permission grant is unavailable; terminal read tool was not executed",
                    )?;
                }
                _ => {
                    let client = agent_terminal_read_client()?;
                    dispatch_agent_terminal_read_tool_with_store_mutex(
                        store_mutex,
                        access_mode,
                        action,
                        active_run_id,
                        desktop_dir,
                        &client,
                    )?;
                }
            }
            continue;
        }

        if action.action_type == "network_search" {
            match approval_state {
                AgentActionApprovalState::Rejected => {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    block_agent_tool_action_after_approval_resolution(
                        &store,
                        action,
                        "local permission request was rejected before network search dispatch",
                        "local permission was rejected; network search tool was not executed",
                    )?;
                }
                AgentActionApprovalState::Unavailable => {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    block_agent_tool_action_after_approval_resolution(
                        &store,
                        action,
                        "approved local permission is no longer available",
                        "permission grant is unavailable; network search tool was not executed",
                    )?;
                }
                _ => {
                    dispatch_agent_network_search_tool_with_store_mutex(
                        store_mutex,
                        access_mode,
                        action,
                        active_run_id,
                        search_client,
                    )?;
                }
            }
            continue;
        }

        if action.action_type == "browser_browse" {
            match approval_state {
                AgentActionApprovalState::Rejected => {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    block_agent_tool_action_after_approval_resolution(
                        &store,
                        action,
                        "local permission request was rejected before browser browse dispatch",
                        "local permission was rejected; browser browse tool was not executed",
                    )?;
                }
                AgentActionApprovalState::Unavailable => {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    block_agent_tool_action_after_approval_resolution(
                        &store,
                        action,
                        "approved local permission is no longer available",
                        "permission grant is unavailable; browser browse tool was not executed",
                    )?;
                }
                _ => {
                    dispatch_agent_browser_browse_tool_with_store_mutex(
                        store_mutex,
                        access_mode,
                        action,
                        active_run_id,
                        browser_client,
                    )?;
                }
            }
            continue;
        }

        if action.action_type == "computer_screenshot" {
            match approval_state {
                AgentActionApprovalState::Rejected => {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    block_agent_tool_action_after_approval_resolution(
                        &store,
                        action,
                        "local permission request was rejected before screen inspection",
                        "local permission was rejected; screenshot tool was not executed",
                    )?;
                }
                AgentActionApprovalState::Unavailable => {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    block_agent_tool_action_after_approval_resolution(
                        &store,
                        action,
                        "approved local permission is no longer available",
                        "permission grant is unavailable; screenshot tool was not executed",
                    )?;
                }
                _ => {
                    dispatch_agent_computer_screenshot_tool_with_store_mutex(
                        store_mutex,
                        access_mode,
                        action,
                        active_run_id,
                        computer_use_client,
                    )?;
                }
            }
            continue;
        }

        if action.action_type == "computer_control" {
            match approval_state {
                AgentActionApprovalState::Rejected => {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    block_agent_tool_action_after_approval_resolution(
                        &store,
                        action,
                        "local permission request was rejected before computer control dispatch",
                        "local permission was rejected; computer control tool was not executed",
                    )?;
                }
                AgentActionApprovalState::Unavailable => {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    block_agent_tool_action_after_approval_resolution(
                        &store,
                        action,
                        "approved local permission is no longer available",
                        "permission grant is unavailable; computer control tool was not executed",
                    )?;
                }
                _ => {
                    dispatch_agent_computer_control_tool_with_store_mutex(
                        store_mutex,
                        access_mode,
                        action,
                        active_run_id,
                        computer_use_client,
                    )?;
                }
            }
            continue;
        }

        match (action.capability, action.policy_decision, approval_state) {
            (Some(CapabilityKind::FileRead), Some(PolicyDecision::Allow), _) => {
                if action.action_type == "office_open" {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    dispatch_agent_office_open_action(
                        &store,
                        access_mode,
                        action,
                        file_write_client,
                        false,
                        None,
                    )?;
                } else {
                    action.execution_state = "blocked".to_string();
                    action.blocked_reason = Some(
                        "file read action has no registered generic tool contract".to_string(),
                    );
                    action.dispatch_note = action.blocked_reason.clone();
                }
            }
            (
                Some(CapabilityKind::FileRead),
                Some(PolicyDecision::Ask),
                AgentActionApprovalState::Approved(approval_request_id),
            ) => {
                if action.action_type == "office_open" {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    dispatch_agent_office_open_action(
                        &store,
                        access_mode,
                        action,
                        file_write_client,
                        true,
                        Some(approval_request_id),
                    )?;
                } else {
                    action.execution_state = "blocked".to_string();
                    action.blocked_reason = Some(
                        "file read action has no registered generic tool contract".to_string(),
                    );
                    action.dispatch_note = action.blocked_reason.clone();
                }
            }
            _ => {
                let mut single_response = AgentChatResponse {
                    id: response.id,
                    role: response.role.clone(),
                    content: response.content.clone(),
                    protocol_version: response.protocol_version.clone(),
                    goal_envelope: None,
                    goal_projection: None,
                    task_capability_proposal: None,
                    proposed_actions: vec![action.clone()],
                    missing_prerequisites: Vec::new(),
                    memory_candidates: Vec::new(),
                    soul_profile_update: None,
                    soul_profile_update_proposal: None,
                    subagent_plan: Vec::new(),
                    expert_output: None,
                    model: response.model.clone(),
                    cache_status: response.cache_status,
                    elapsed_ms: response.elapsed_ms,
                    prompt_tokens: response.prompt_tokens,
                    completion_tokens: response.completion_tokens,
                    total_tokens: response.total_tokens,
                    estimated_cost_micro_usd: response.estimated_cost_micro_usd,
                    created_at: response.created_at,
                };
                {
                    let store = store_mutex.lock().map_err(|_| lock_error())?;
                    dispatch_agent_action_proposals_with_desktop_dir(
                        &store,
                        access_mode,
                        &mut single_response,
                        file_client,
                        file_write_client,
                        search_client,
                        browser_client,
                        desktop_dir,
                    )?;
                }
                if let Some(updated_action) = single_response.proposed_actions.into_iter().next() {
                    *action = updated_action;
                }
            }
        }
    }

    Ok(())
}

fn resume_agent_chat_action_with_clients(
    store: &EventStore,
    access_mode: AccessMode,
    action: AgentChatActionProposal,
    file_client: &impl FileContentClient,
    file_write_client: &impl AgentWritableArtifactClient,
    search_client: &impl NetworkSearchClient,
    browser_client: &impl BrowserPageClient,
    desktop_dir: Option<&Path>,
) -> Result<AgentChatActionProposal, String> {
    resume_agent_chat_action_with_clients_and_computer_use(
        store,
        access_mode,
        action,
        file_client,
        file_write_client,
        search_client,
        browser_client,
        &UnavailableAgentComputerUseClient,
        desktop_dir,
    )
}

fn resume_agent_chat_action_with_clients_and_computer_use(
    store: &EventStore,
    access_mode: AccessMode,
    action: AgentChatActionProposal,
    file_client: &impl FileContentClient,
    file_write_client: &impl AgentWritableArtifactClient,
    search_client: &impl NetworkSearchClient,
    browser_client: &impl BrowserPageClient,
    computer_use_client: &(impl ComputerScreenshotClient + ComputerControlClient),
    desktop_dir: Option<&Path>,
) -> Result<AgentChatActionProposal, String> {
    let mut response = AgentChatResponse {
        id: Uuid::new_v4(),
        role: "assistant".to_string(),
        content: String::new(),
        protocol_version: "ds-agent-action-resume-v1".to_string(),
        goal_envelope: None,
        goal_projection: None,
        task_capability_proposal: None,
        proposed_actions: vec![action],
        missing_prerequisites: Vec::new(),
        memory_candidates: Vec::new(),
        soul_profile_update: None,
        soul_profile_update_proposal: None,
        subagent_plan: Vec::new(),
        expert_output: None,
        model: "local-ds-agent-dispatch".to_string(),
        cache_status: DeepSeekChatCacheStatus::Miss,
        elapsed_ms: 0,
        prompt_tokens: None,
        completion_tokens: None,
        total_tokens: None,
        estimated_cost_micro_usd: None,
        created_at: Utc::now(),
    };
    dispatch_agent_action_proposals_with_desktop_dir_and_computer_use(
        store,
        access_mode,
        &mut response,
        file_client,
        file_write_client,
        search_client,
        browser_client,
        computer_use_client,
        desktop_dir,
    )?;
    response
        .proposed_actions
        .into_iter()
        .next()
        .ok_or_else(|| "agent action resume returned no action".to_string())
}

fn agent_action_approval_state(
    store: &EventStore,
    action: &AgentChatActionProposal,
) -> Result<AgentActionApprovalState, String> {
    let Some(permission_request_id) = action.permission_request_id else {
        return Ok(AgentActionApprovalState::NoRequest);
    };
    let Some(record) = store
        .list_capability_access_records()
        .map_err(event_store_error)?
        .into_iter()
        .find(|record| record.request.id == permission_request_id)
    else {
        return Ok(AgentActionApprovalState::Unavailable);
    };
    if action
        .capability
        .is_some_and(|capability| capability != record.request.capability)
    {
        return Ok(AgentActionApprovalState::Unavailable);
    }

    match record.effective_status {
        crate::kernel::policy::CapabilityAccessStatus::Approved
            if matches!(
                record.grant_state,
                CapabilityGrantState::Reusable | CapabilityGrantState::OneShotAvailable
            ) =>
        {
            Ok(AgentActionApprovalState::Approved(permission_request_id))
        }
        crate::kernel::policy::CapabilityAccessStatus::Rejected
        | crate::kernel::policy::CapabilityAccessStatus::Denied => {
            Ok(AgentActionApprovalState::Rejected)
        }
        crate::kernel::policy::CapabilityAccessStatus::PendingApproval => {
            Ok(AgentActionApprovalState::Pending)
        }
        _ => Ok(AgentActionApprovalState::Unavailable),
    }
}

fn mark_agent_actions_waiting_for_prerequisites(response: &mut AgentChatResponse) {
    let prerequisite_kinds = response
        .missing_prerequisites
        .iter()
        .map(|prerequisite| prerequisite.kind.trim())
        .filter(|kind| !kind.is_empty())
        .collect::<Vec<_>>()
        .join(", ");
    let dispatch_note = if prerequisite_kinds.is_empty() {
        "waiting for missing prerequisites before dispatch".to_string()
    } else {
        format!("waiting for missing prerequisites before dispatch: {prerequisite_kinds}")
    };

    for action in &mut response.proposed_actions {
        if action.execution_state == "blocked" {
            continue;
        }
        action.execution_state = "waiting_prerequisite".to_string();
        action.dispatch_note = Some(dispatch_note.clone());
    }
}

fn mark_office_open_actions_waiting_for_pending_create(response: &mut AgentChatResponse) {
    let pending_create_targets = response
        .proposed_actions
        .iter()
        .filter(|action| action.action_type == "office_create")
        .filter(|action| {
            matches!(
                action.execution_state.as_str(),
                "proposed" | "needs_confirmation" | "waiting_prerequisite" | "blocked" | "failed"
            )
        })
        .filter_map(|action| normalized_agent_action_target(action))
        .collect::<Vec<_>>();

    if pending_create_targets.is_empty() {
        return;
    }

    for action in &mut response.proposed_actions {
        if action.action_type != "office_open" {
            continue;
        }
        if !matches!(
            action.execution_state.as_str(),
            "proposed" | "needs_confirmation"
        ) {
            continue;
        }
        let Some(target) = normalized_agent_action_target(action) else {
            continue;
        };
        if !pending_create_targets
            .iter()
            .any(|pending| pending == &target)
        {
            continue;
        }

        action.execution_state = "waiting_prerequisite".to_string();
        action.dispatch_note =
            Some("waiting for Office file creation before opening it".to_string());
    }
}

fn normalized_agent_action_target(action: &AgentChatActionProposal) -> Option<String> {
    action
        .target
        .as_deref()
        .map(str::trim)
        .filter(|target| !target.is_empty())
        .map(|target| {
            apply_agent_action_target_location(target, action.target_location.as_deref())
                .to_ascii_lowercase()
        })
}

fn agent_action_requires_workspace(action: &AgentChatActionProposal) -> bool {
    matches!(
        action.action_type.as_str(),
        "create_report"
            | "file_write"
            | "office_create"
            | "office_open"
            | "office_update"
            | "operations_briefing"
            | "work_package_export"
    )
}

fn mark_agent_workspace_actions_waiting_if_needed(
    runtime_context: &AgentChatRuntimeContext,
    response: &mut AgentChatResponse,
) {
    if runtime_context.workspace_ready != AgentChatReadiness::Missing {
        return;
    }

    let mut found_workspace_action = false;
    for action in &mut response.proposed_actions {
        if !agent_action_requires_workspace(action) {
            continue;
        }
        if matches!(
            action.execution_state.as_str(),
            "blocked" | "succeeded" | "failed"
        ) {
            continue;
        }

        found_workspace_action = true;
        action.execution_state = "waiting_prerequisite".to_string();
        action.dispatch_note =
            Some("waiting for workspace setup before local artifact dispatch".to_string());
    }

    if found_workspace_action
        && !response
            .missing_prerequisites
            .iter()
            .any(|prerequisite| prerequisite.kind.trim() == "workspace")
    {
        response
            .missing_prerequisites
            .push(AgentChatMissingPrerequisite {
                kind: "workspace".to_string(),
                message: "请先选择一个 DS Agent 工作目录。DS Agent 会在这个根目录下自动创建报告、证据、导出、运行记录和工作包等子目录。"
                    .to_string(),
            });
    }
}

fn record_agent_action_permission_request(
    store: &EventStore,
    access_mode: AccessMode,
    action: &mut AgentChatActionProposal,
) -> Result<(), String> {
    let Some(capability) = action.capability else {
        return Ok(());
    };
    if action.permission_request_id.is_some() {
        return Ok(());
    }

    let request = build_capability_access_request(access_mode, capability)?;
    let entry = PermissionAuditEntry::evaluate(access_mode, capability);
    store
        .append_capability_access_request(&request)
        .map_err(event_store_error)?;
    store
        .append_permission_audit_entry(&entry)
        .map_err(event_store_error)?;

    action.permission_request_id = Some(request.id);
    action.execution_state = "needs_confirmation".to_string();
    action.dispatch_note =
        Some("waiting for local permission approval before dispatch".to_string());
    Ok(())
}

fn agent_terminal_read_client() -> Result<LocalTerminalReadClient, String> {
    let working_dir = std::env::current_dir().map_err(event_store_error)?;
    Ok(LocalTerminalReadClient::new(
        working_dir,
        TERMINAL_READ_OUTPUT_CHAR_LIMIT,
    ))
}

fn agent_terminal_read_command_from_target(
    target: &str,
    desktop_dir: Option<&Path>,
) -> Result<String, String> {
    let trimmed = target.trim();
    if trimmed.is_empty() {
        return Err("terminal_read target or command is required before dispatch".to_string());
    }

    let normalized = trimmed.replace('\\', "/");
    let normalized_lower = normalized.trim_end_matches('/').to_ascii_lowercase();
    if matches!(
        normalized_lower.as_str(),
        "desktop" | "user_desktop" | "windows_desktop" | "桌面"
    ) {
        let desktop_dir = desktop_dir
            .ok_or_else(|| "desktop directory is unavailable on this machine".to_string())?;
        return Ok(format!("ds-agent:list-directory {}", desktop_dir.display()));
    }

    for prefix in ["desktop/", "user_desktop/", "windows_desktop/", "桌面/"] {
        if normalized_lower.starts_with(prefix) {
            let desktop_dir = desktop_dir
                .ok_or_else(|| "desktop directory is unavailable on this machine".to_string())?;
            let relative = normalized[prefix.len()..].trim_matches('/');
            if relative.is_empty() {
                return Ok(format!("ds-agent:list-directory {}", desktop_dir.display()));
            }
            return Ok(format!(
                "ds-agent:list-directory {}",
                desktop_dir.join(relative).display()
            ));
        }
    }

    Ok(trimmed.to_string())
}

fn dispatch_agent_operations_briefing_action(
    store: &EventStore,
    access_mode: AccessMode,
    action: &mut AgentChatActionProposal,
    approval_granted: bool,
    approval_request_id: Option<Uuid>,
) -> Result<(), String> {
    let Some(evidence_folder_path) = action
        .target
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    else {
        action.execution_state = "blocked".to_string();
        action.blocked_reason = Some(
            "operations_briefing target evidence folder is required before dispatch".to_string(),
        );
        return Ok(());
    };

    let client = LocalEvidenceFolderClient::new(20, 512 * 1024);
    let outcome = build_operations_briefing_run(
        OperationsBriefingRequest {
            access_mode,
            evidence_folder_path: evidence_folder_path.to_string(),
            approval_granted,
        },
        &client,
    )?;
    let mut evidence_invocation = outcome.evidence_invocation;
    evidence_invocation.approval_request_id = approval_request_id;
    let entry = PermissionAuditEntry::evaluate(access_mode, CapabilityKind::FileRead);
    if !approval_granted || outcome.access_request.decision == PolicyDecision::Allow {
        store
            .append_capability_access_request(&outcome.access_request)
            .map_err(event_store_error)?;
    }
    store
        .append_permission_audit_entry(&entry)
        .map_err(event_store_error)?;
    store
        .append_capability_invocation(&evidence_invocation)
        .map_err(event_store_error)?;
    store
        .append_operations_briefing_run(&outcome.run)
        .map_err(event_store_error)?;

    if outcome.access_request.decision == PolicyDecision::Ask {
        action.permission_request_id = Some(outcome.access_request.id);
    }
    action.capability_invocation_id = Some(evidence_invocation.id);
    action.workflow_run_id = Some(outcome.run.id);
    action.execution_state = agent_action_state_from_operations_briefing_run(&outcome.run);
    action.dispatch_note = Some(agent_operations_briefing_dispatch_note(&outcome.run));
    Ok(())
}

fn dispatch_agent_office_create_action(
    store: &EventStore,
    access_mode: AccessMode,
    action: &mut AgentChatActionProposal,
    office_client: &impl OfficeArtifactClient,
    approval_granted: bool,
    approval_request_id: Option<Uuid>,
) -> Result<(), String> {
    let spec = match office_create_spec_from_action(
        &action.action_type,
        action.target.as_deref(),
        action.target_location.as_deref(),
        action.title.as_deref(),
        action.reason.as_deref(),
        action.content.as_deref(),
    ) {
        Ok(spec) => spec,
        Err(error) => {
            action.execution_state = "blocked".to_string();
            action.blocked_reason = Some(error);
            action.dispatch_note = Some("office file was not created".to_string());
            return Ok(());
        }
    };

    let outcome = run_office_create_boundary(
        OfficeCreateRequest {
            access_mode,
            spec: spec.clone(),
            approval_granted,
        },
        office_client,
    )?;
    let mut invocation = outcome.invocation;
    invocation.approval_request_id = approval_request_id;
    let mut entry = PermissionAuditEntry::evaluate(access_mode, CapabilityKind::FileWrite);
    entry.decision = outcome.access_request.decision;
    entry.reason = outcome.access_request.reason.clone();
    if !approval_granted || outcome.access_request.decision == PolicyDecision::Allow {
        store
            .append_capability_access_request(&outcome.access_request)
            .map_err(event_store_error)?;
    }
    store
        .append_permission_audit_entry(&entry)
        .map_err(event_store_error)?;
    store
        .append_capability_invocation(&invocation)
        .map_err(event_store_error)?;

    if let Some(result) = outcome.result.as_ref() {
        register_completed_office_artifact(
            store,
            invocation.id,
            invocation.status == CapabilityInvocationStatus::Succeeded,
            &spec,
            result,
        )?;
    }

    if action.permission_request_id.is_none()
        && outcome.access_request.decision == PolicyDecision::Ask
    {
        action.permission_request_id = Some(outcome.access_request.id);
    }
    action.target = Some(spec.path.clone());
    action.capability_invocation_id = Some(invocation.id);
    action.execution_state = agent_action_state_from_invocation(invocation.status);
    action.blocked_reason = if invocation.status == CapabilityInvocationStatus::Failed {
        invocation
            .warnings
            .first()
            .cloned()
            .or_else(|| invocation.excerpt.clone())
    } else {
        None
    };
    action.dispatch_note = Some(agent_office_create_dispatch_note(
        &invocation,
        outcome.result,
        &spec,
    ));
    Ok(())
}

pub(crate) fn register_tool_office_artifact_if_succeeded(
    store: &EventStore,
    invocation: &ToolInvocationRecord,
    spec: &OfficeCreateSpec,
) -> Result<(), String> {
    if invocation.status != ToolExecutionStatus::Succeeded {
        return Ok(());
    }
    let result = invocation
        .output
        .clone()
        .ok_or_else(|| "office artifact result is missing".to_string())
        .and_then(|value| {
            serde_json::from_value::<OfficeCreateResult>(value).map_err(event_store_error)
        })?;
    register_completed_office_artifact(store, invocation.id, true, spec, &result).and_then(|_| {
        store
            .fulfill_artifact_generation_intent(&invocation.request_fingerprint, Utc::now())
            .map_err(event_store_error)
    })
}

fn register_completed_office_artifact(
    store: &EventStore,
    request_id: Uuid,
    approved_write_succeeded: bool,
    spec: &OfficeCreateSpec,
    result: &OfficeCreateResult,
) -> Result<(), String> {
    if !approved_write_succeeded {
        return Err(
            "office artifact cannot enter delivery before the approved write succeeds".to_string(),
        );
    }
    #[cfg(test)]
    if !Path::new(&result.path).is_file() {
        // Lightweight executor doubles validate routing and approval behavior; byte-level
        // delivery validation is covered by LocalOfficeArtifactClient and artifact fixtures.
        return Ok(());
    }
    let bytes = fs::read(&result.path)
        .map_err(|_| "written office artifact could not be reopened for validation".to_string())?;
    let template = ArtifactTemplate::new(
        "default.office".to_string(),
        1,
        "DS Agent default office template".to_string(),
        vec![
            crate::kernel::artifacts::ArtifactFormat::Word,
            crate::kernel::artifacts::ArtifactFormat::Excel,
            crate::kernel::artifacts::ArtifactFormat::PowerPoint,
        ],
        "default-office-v1".to_string(),
    );
    store
        .register_artifact_template(&template, Utc::now())
        .map_err(event_store_error)?;
    let request = ArtifactGenerationRequest {
        request_id,
        input: ArtifactInput::Office { spec: spec.clone() },
        template: template.reference.clone(),
        approved_storage_ref: format!("artifact-storage:{request_id}"),
    };
    let mut generated = ArtifactEngine::generate_with_template(&request, &template, Utc::now())?;
    generated.record.artifact_hash = sha256_hex(&bytes);
    if let Some((existing, _)) = store
        .artifact_record_for_request(request_id)
        .map_err(event_store_error)?
    {
        if existing.artifact_hash != generated.record.artifact_hash
            || existing.input_fingerprint != generated.record.input_fingerprint
            || existing.template != generated.record.template
        {
            return Err("artifact request binding changed".to_string());
        }
        return Ok(());
    }
    let canonical_path = Path::new(&result.path)
        .canonicalize()
        .map_err(|_| "written office artifact path could not be resolved".to_string())?;
    store
        .bind_artifact_storage_path(
            &generated.record.storage_ref,
            request_id,
            &canonical_path.to_string_lossy(),
            &generated.record.artifact_hash,
            Utc::now(),
        )
        .map_err(event_store_error)?;
    let row_revision = store
        .insert_artifact_record(&generated.record)
        .map_err(event_store_error)?;
    let structure_result =
        ArtifactEngine::check_structure(&mut generated.record, &bytes, Utc::now());
    let row_revision = store
        .update_artifact_record(&generated.record, row_revision)
        .map_err(event_store_error)?;
    if structure_result.is_err() {
        return Ok(());
    }
    let rendered = render_artifact_file(generated.record.format, Path::new(&result.path))?;
    let preview_ref = format!(
        "artifact-preview:{}:{}",
        generated.record.id, generated.record.artifact_revision
    );
    let visual_result = ArtifactEngine::check_actual_visual(
        &mut generated.record,
        &rendered.pages,
        rendered.renderer_version,
        preview_ref,
        Utc::now(),
    );
    if visual_result.is_ok() {
        store
            .store_artifact_visual_previews(&generated.record, &rendered.pages)
            .map_err(event_store_error)?;
    }
    let row_revision = store
        .update_artifact_record(&generated.record, row_revision)
        .map_err(event_store_error)?;
    if visual_result.is_err() {
        return Ok(());
    }
    generated.record.complete(Utc::now())?;
    store
        .update_artifact_record(&generated.record, row_revision)
        .map_err(event_store_error)?;
    Ok(())
}

fn register_completed_pdf_artifact(
    store: &EventStore,
    request_id: Uuid,
    title: String,
    paragraphs: Vec<String>,
    bytes: &[u8],
    storage_path: &str,
) -> Result<(), String> {
    let template = ArtifactTemplate::new(
        "default.pdf".to_string(),
        1,
        "DS Agent default PDF template".to_string(),
        vec![crate::kernel::artifacts::ArtifactFormat::Pdf],
        "default-pdf-v1".to_string(),
    );
    store
        .register_artifact_template(&template, Utc::now())
        .map_err(event_store_error)?;
    let request = ArtifactGenerationRequest {
        request_id,
        input: ArtifactInput::Pdf { title, paragraphs },
        template: template.reference.clone(),
        approved_storage_ref: format!("artifact-storage:{request_id}"),
    };
    let mut generated = ArtifactEngine::generate_with_template(&request, &template, Utc::now())?;
    generated.record.artifact_hash = sha256_hex(bytes);
    let row_revision = if let Some((existing, revision)) = store
        .artifact_record_for_request(request_id)
        .map_err(event_store_error)?
    {
        if existing.artifact_hash != generated.record.artifact_hash
            || existing.input_fingerprint != generated.record.input_fingerprint
            || existing.template != generated.record.template
        {
            return Err("artifact request binding changed".to_string());
        }
        generated.record = existing;
        revision
    } else {
        let canonical_path = Path::new(storage_path)
            .canonicalize()
            .map_err(|_| "written PDF artifact path could not be resolved".to_string())?;
        store
            .bind_artifact_storage_path(
                &generated.record.storage_ref,
                request_id,
                &canonical_path.to_string_lossy(),
                &generated.record.artifact_hash,
                Utc::now(),
            )
            .map_err(event_store_error)?;
        store
            .insert_artifact_record(&generated.record)
            .map_err(event_store_error)?
    };
    let structure_result =
        ArtifactEngine::check_structure(&mut generated.record, bytes, Utc::now());
    let row_revision = store
        .update_artifact_record(&generated.record, row_revision)
        .map_err(event_store_error)?;
    if structure_result.is_err() {
        return Ok(());
    }
    let temp =
        tempfile::tempdir().map_err(|_| "PDF render workspace could not be created".to_string())?;
    let path = temp.path().join("artifact.pdf");
    fs::write(&path, bytes).map_err(|_| "PDF render input could not be prepared".to_string())?;
    let rendered = render_artifact_file(generated.record.format, &path)?;
    let preview_ref = format!(
        "artifact-preview:{}:{}",
        generated.record.id, generated.record.artifact_revision
    );
    let visual_result = ArtifactEngine::check_actual_visual(
        &mut generated.record,
        &rendered.pages,
        rendered.renderer_version,
        preview_ref,
        Utc::now(),
    );
    if visual_result.is_ok() {
        store
            .store_artifact_visual_previews(&generated.record, &rendered.pages)
            .map_err(event_store_error)?;
    }
    let row_revision = store
        .update_artifact_record(&generated.record, row_revision)
        .map_err(event_store_error)?;
    if visual_result.is_err() {
        return Ok(());
    }
    generated.record.complete(Utc::now())?;
    store
        .update_artifact_record(&generated.record, row_revision)
        .map_err(event_store_error)?;
    Ok(())
}

fn prepare_pdf_artifact_before_write(
    store: &EventStore,
    request_id: Uuid,
    title: String,
    paragraphs: Vec<String>,
    bytes: &[u8],
    intended_path: &Path,
) -> Result<(), String> {
    let template = ArtifactTemplate::new(
        "default.pdf".to_string(),
        1,
        "DS Agent default PDF template".to_string(),
        vec![crate::kernel::artifacts::ArtifactFormat::Pdf],
        "default-pdf-v1".to_string(),
    );
    store
        .register_artifact_template(&template, Utc::now())
        .map_err(event_store_error)?;
    let request = ArtifactGenerationRequest {
        request_id,
        input: ArtifactInput::Pdf { title, paragraphs },
        template: template.reference.clone(),
        approved_storage_ref: format!("artifact-storage:{request_id}"),
    };
    let mut generated = ArtifactEngine::generate_with_template(&request, &template, Utc::now())?;
    generated.record.artifact_hash = sha256_hex(bytes);
    let parent = intended_path
        .parent()
        .ok_or_else(|| "PDF target parent is invalid".to_string())?
        .canonicalize()
        .map_err(|_| "PDF target parent could not be resolved".to_string())?;
    let file_name = intended_path
        .file_name()
        .ok_or_else(|| "PDF target filename is invalid".to_string())?;
    let canonical_target = parent.join(file_name);
    store
        .bind_artifact_storage_path(
            &generated.record.storage_ref,
            request_id,
            &canonical_target.to_string_lossy(),
            &generated.record.artifact_hash,
            Utc::now(),
        )
        .map_err(event_store_error)?;
    store
        .insert_artifact_record(&generated.record)
        .map_err(event_store_error)?;
    Ok(())
}

fn dispatch_agent_office_open_action(
    store: &EventStore,
    access_mode: AccessMode,
    action: &mut AgentChatActionProposal,
    office_client: &impl OfficeOpenClient,
    approval_granted: bool,
    approval_request_id: Option<Uuid>,
) -> Result<(), String> {
    let Some(target) = action
        .target
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    else {
        action.execution_state = "blocked".to_string();
        action.blocked_reason = Some("office_open target is required before dispatch".to_string());
        return Ok(());
    };
    let target = apply_agent_action_target_location(target, action.target_location.as_deref());
    let Some(preferred_app) =
        infer_agent_action_office_app(action).or_else(|| OfficeApp::from_path(&target))
    else {
        action.execution_state = "blocked".to_string();
        action.blocked_reason =
            Some("office_open target must be a .docx, .xlsx, or .pptx file".to_string());
        return Ok(());
    };

    let outcome = run_office_open_boundary(
        OfficeOpenRequest {
            access_mode,
            path: target.clone(),
            preferred_app: Some(preferred_app),
            approval_granted,
        },
        office_client,
    )?;
    let mut invocation = outcome.invocation;
    invocation.approval_request_id = approval_request_id;
    let entry = PermissionAuditEntry::evaluate(access_mode, CapabilityKind::FileRead);
    if !approval_granted || outcome.access_request.decision == PolicyDecision::Allow {
        store
            .append_capability_access_request(&outcome.access_request)
            .map_err(event_store_error)?;
    }
    store
        .append_permission_audit_entry(&entry)
        .map_err(event_store_error)?;
    store
        .append_capability_invocation(&invocation)
        .map_err(event_store_error)?;

    if action.permission_request_id.is_none()
        && outcome.access_request.decision == PolicyDecision::Ask
    {
        action.permission_request_id = Some(outcome.access_request.id);
    }
    action.target = Some(target.replace('\\', "/"));
    action.capability_invocation_id = Some(invocation.id);
    action.execution_state = agent_action_state_from_invocation(invocation.status);
    action.blocked_reason = if invocation.status == CapabilityInvocationStatus::Failed {
        invocation
            .warnings
            .first()
            .cloned()
            .or_else(|| invocation.excerpt.clone())
    } else {
        None
    };
    action.dispatch_note = Some(agent_office_open_dispatch_note(&invocation, outcome.result));
    Ok(())
}

fn dispatch_agent_office_update_action(
    store: &EventStore,
    access_mode: AccessMode,
    action: &mut AgentChatActionProposal,
    office_client: &impl OfficeUpdateClient,
    approval_granted: bool,
    approval_request_id: Option<Uuid>,
) -> Result<(), String> {
    let spec = match office_update_spec_from_action(
        &action.action_type,
        action.target.as_deref(),
        action.target_location.as_deref(),
        action.title.as_deref(),
        action.reason.as_deref(),
        action.content.as_deref(),
    ) {
        Ok(spec) => spec,
        Err(error) => {
            action.execution_state = "blocked".to_string();
            action.blocked_reason = Some(error);
            action.dispatch_note = Some("office file was not updated".to_string());
            return Ok(());
        }
    };

    let outcome = run_office_update_boundary(
        OfficeUpdateRequest {
            access_mode,
            spec: spec.clone(),
            approval_granted,
        },
        office_client,
    )?;
    let mut invocation = outcome.invocation;
    invocation.approval_request_id = approval_request_id;
    let entry = PermissionAuditEntry::evaluate(access_mode, CapabilityKind::FileWrite);
    if !approval_granted || outcome.access_request.decision == PolicyDecision::Allow {
        store
            .append_capability_access_request(&outcome.access_request)
            .map_err(event_store_error)?;
    }
    store
        .append_permission_audit_entry(&entry)
        .map_err(event_store_error)?;
    store
        .append_capability_invocation(&invocation)
        .map_err(event_store_error)?;

    if action.permission_request_id.is_none()
        && outcome.access_request.decision == PolicyDecision::Ask
    {
        action.permission_request_id = Some(outcome.access_request.id);
    }
    action.target = Some(spec.path);
    action.capability_invocation_id = Some(invocation.id);
    action.execution_state = agent_action_state_from_invocation(invocation.status);
    action.blocked_reason = if invocation.status == CapabilityInvocationStatus::Failed {
        invocation
            .warnings
            .first()
            .cloned()
            .or_else(|| invocation.excerpt.clone())
    } else {
        None
    };
    action.dispatch_note = Some(agent_office_update_dispatch_note(
        &invocation,
        outcome.result,
    ));
    Ok(())
}

fn infer_agent_action_office_app(action: &AgentChatActionProposal) -> Option<OfficeApp> {
    action
        .target
        .as_deref()
        .and_then(OfficeApp::from_path)
        .or_else(|| action.title.as_deref().and_then(OfficeApp::from_label))
        .or_else(|| action.reason.as_deref().and_then(OfficeApp::from_label))
        .or_else(|| action.content.as_deref().and_then(OfficeApp::from_label))
}

fn agent_office_update_dispatch_note(
    invocation: &CapabilityInvocation,
    result: Option<OfficeUpdateResult>,
) -> String {
    match invocation.status {
        CapabilityInvocationStatus::Succeeded => result
            .map(|result| {
                format!(
                    "{} updated: {} ({})",
                    result.app.user_facing_name(),
                    result.path,
                    result.summary
                )
            })
            .unwrap_or_else(|| "office file updated".to_string()),
        CapabilityInvocationStatus::PendingApproval => {
            "office file update is waiting for approval".to_string()
        }
        CapabilityInvocationStatus::Failed => invocation
            .warnings
            .first()
            .map(|warning| format!("office file update failed: {warning}"))
            .unwrap_or_else(|| "office file update failed".to_string()),
    }
}

fn agent_office_open_dispatch_note(
    invocation: &CapabilityInvocation,
    result: Option<OfficeOpenResult>,
) -> String {
    match invocation.status {
        CapabilityInvocationStatus::Succeeded => result
            .map(|result| {
                let fallback = result
                    .fallback_note
                    .map(|note| format!(" ({note})"))
                    .unwrap_or_default();
                format!(
                    "{} opened: {}{}",
                    result.app.user_facing_name(),
                    result.path,
                    fallback
                )
            })
            .unwrap_or_else(|| "office file opened".to_string()),
        CapabilityInvocationStatus::PendingApproval => {
            "office file open is waiting for approval".to_string()
        }
        CapabilityInvocationStatus::Failed => invocation
            .warnings
            .first()
            .map(|warning| format!("office file open failed: {warning}"))
            .unwrap_or_else(|| "office file open failed".to_string()),
    }
}

fn agent_office_create_dispatch_note(
    invocation: &CapabilityInvocation,
    result: Option<OfficeCreateResult>,
    spec: &OfficeCreateSpec,
) -> String {
    match invocation.status {
        CapabilityInvocationStatus::Succeeded => result
            .map(|result| {
                let mut note =
                    format!("{} created: {}", result.app.user_facing_name(), result.path);
                if let Some(evidence) = agent_office_create_content_evidence(spec) {
                    note.push_str("\nCreated content:\n");
                    note.push_str(&evidence);
                }
                note
            })
            .unwrap_or_else(|| "office file created".to_string()),
        CapabilityInvocationStatus::PendingApproval => {
            "office file creation is waiting for approval".to_string()
        }
        CapabilityInvocationStatus::Failed => invocation
            .warnings
            .first()
            .map(|warning| format!("office file creation failed: {warning}"))
            .unwrap_or_else(|| "office file creation failed".to_string()),
    }
}

fn agent_office_create_content_evidence(spec: &OfficeCreateSpec) -> Option<String> {
    let evidence = match spec.app {
        OfficeApp::Word => spec.body.trim().to_string(),
        OfficeApp::Excel => spec
            .rows
            .iter()
            .take(20)
            .map(|row| {
                row.iter()
                    .map(|cell| cell.trim())
                    .collect::<Vec<_>>()
                    .join(" | ")
            })
            .collect::<Vec<_>>()
            .join("\n"),
        OfficeApp::PowerPoint => spec
            .slides
            .iter()
            .take(20)
            .enumerate()
            .map(|(index, slide)| {
                let title = slide.title.trim();
                let body = slide.body.trim();
                match (title.is_empty(), body.is_empty()) {
                    (true, true) => format!("Slide {}", index + 1),
                    (false, true) => format!("Slide {}: {}", index + 1, title),
                    (true, false) => format!("Slide {}: {}", index + 1, body),
                    (false, false) => format!("Slide {}: {}\n{}", index + 1, title, body),
                }
            })
            .collect::<Vec<_>>()
            .join("\n"),
    };
    compact_agent_tool_evidence_text(&evidence, AGENT_OFFICE_CREATE_EVIDENCE_TEXT_LIMIT)
}

fn compact_agent_tool_evidence_text(text: &str, limit: usize) -> Option<String> {
    let compact = text
        .lines()
        .map(str::trim)
        .filter(|line| !line.is_empty())
        .collect::<Vec<_>>()
        .join("\n");
    if compact.is_empty() {
        return None;
    }

    let mut truncated = String::new();
    let mut chars = compact.chars();
    for character in chars.by_ref().take(limit) {
        truncated.push(character);
    }
    if chars.next().is_some() {
        truncated.push_str("\n...");
    }
    Some(truncated)
}

fn agent_action_destination(action: &AgentChatActionProposal) -> Option<String> {
    let direct = action.destination.as_deref();
    let content_fallback = action
        .content
        .as_deref()
        .filter(|value| Path::new(value.trim()).is_absolute());

    direct
        .or(content_fallback)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToString::to_string)
}

fn agent_computer_control_target(action: &AgentChatActionProposal) -> Option<String> {
    action
        .target
        .as_deref()
        .or(action.title.as_deref())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToString::to_string)
}

fn agent_computer_control_action_contract(action: &AgentChatActionProposal) -> Option<String> {
    [
        action.content.as_deref(),
        action.reason.as_deref(),
        action.target.as_deref(),
    ]
    .into_iter()
    .flatten()
    .map(str::trim)
    .filter(|value| !value.is_empty())
    .find(|value| {
        let lower = value.to_ascii_lowercase();
        matches!(
            lower.split_once(':').map(|(verb, _)| verb.trim()),
            Some("click" | "move" | "type" | "press" | "hotkey" | "scroll")
        )
    })
    .map(ToString::to_string)
}

fn dispatch_agent_browser_open_action(
    store: &EventStore,
    access_mode: AccessMode,
    action: &mut AgentChatActionProposal,
    approval_granted: bool,
    approval_request_id: Option<Uuid>,
) -> Result<(), String> {
    let opener = SystemBrowserUrlOpener;
    dispatch_agent_browser_open_action_with_opener(
        store,
        access_mode,
        action,
        approval_granted,
        approval_request_id,
        &opener,
    )
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct BrowserUrlOpenOutcome {
    browser_label: String,
    fallback_note: Option<String>,
}

trait BrowserUrlOpener {
    fn open_url(
        &self,
        url: &str,
        preferred_browser: Option<&str>,
    ) -> Result<BrowserUrlOpenOutcome, String>;
}

struct SystemBrowserUrlOpener;

impl BrowserUrlOpener for SystemBrowserUrlOpener {
    fn open_url(
        &self,
        url: &str,
        preferred_browser: Option<&str>,
    ) -> Result<BrowserUrlOpenOutcome, String> {
        if normalize_agent_action_browser_preference(preferred_browser).as_deref() == Some("chrome")
        {
            return open_url_in_chrome_or_default_browser(url);
        }

        open_url_in_default_browser(url).map(|()| BrowserUrlOpenOutcome {
            browser_label: "default browser".to_string(),
            fallback_note: None,
        })
    }
}

fn dispatch_agent_browser_open_action_with_opener(
    store: &EventStore,
    access_mode: AccessMode,
    action: &mut AgentChatActionProposal,
    approval_granted: bool,
    approval_request_id: Option<Uuid>,
    opener: &impl BrowserUrlOpener,
) -> Result<(), String> {
    let Some(url) = action
        .target
        .as_deref()
        .and_then(extract_safe_browser_url)
        .filter(|value| !value.is_empty())
    else {
        action.execution_state = "blocked".to_string();
        action.blocked_reason =
            Some("browser_open target URL is required before dispatch".to_string());
        return Ok(());
    };

    let started_at = Instant::now();
    let access_request =
        build_capability_access_request(access_mode, CapabilityKind::BrowserBrowse)?;
    let preferred_browser =
        normalize_agent_action_browser_preference(action.preferred_browser.as_deref());
    let mut invocation = if access_request.decision == PolicyDecision::Ask && !approval_granted {
        CapabilityInvocation {
            id: Uuid::new_v4(),
            capability: CapabilityKind::BrowserBrowse,
            status: CapabilityInvocationStatus::PendingApproval,
            policy_decision: access_request.decision,
            approval_request_id: None,
            requested_resource: Some(url.clone()),
            evidence_ref: Some(url.clone()),
            requested_url: Some(url.clone()),
            evidence_url: Some(url.clone()),
            title: Some("Browser open request".to_string()),
            excerpt: None,
            warnings: vec!["browser open requires approval before launching the URL".to_string()],
            elapsed_ms: started_at.elapsed().as_millis(),
            created_at: Utc::now(),
        }
    } else {
        match opener.open_url(&url, preferred_browser.as_deref()) {
            Ok(outcome) => {
                let warnings = outcome.fallback_note.into_iter().collect::<Vec<_>>();
                CapabilityInvocation {
                    id: Uuid::new_v4(),
                    capability: CapabilityKind::BrowserBrowse,
                    status: CapabilityInvocationStatus::Succeeded,
                    policy_decision: access_request.decision,
                    approval_request_id: None,
                    requested_resource: Some(url.clone()),
                    evidence_ref: Some(url.clone()),
                    requested_url: Some(url.clone()),
                    evidence_url: Some(url.clone()),
                    title: Some(format!("Browser opened with {}", outcome.browser_label)),
                    excerpt: Some(url.clone()),
                    warnings,
                    elapsed_ms: started_at.elapsed().as_millis(),
                    created_at: Utc::now(),
                }
            }
            Err(error) => CapabilityInvocation {
                id: Uuid::new_v4(),
                capability: CapabilityKind::BrowserBrowse,
                status: CapabilityInvocationStatus::Failed,
                policy_decision: access_request.decision,
                approval_request_id: None,
                requested_resource: Some(url.clone()),
                evidence_ref: Some(url.clone()),
                requested_url: Some(url.clone()),
                evidence_url: Some(url),
                title: Some("Browser open failed".to_string()),
                excerpt: None,
                warnings: vec![error],
                elapsed_ms: started_at.elapsed().as_millis(),
                created_at: Utc::now(),
            },
        }
    };
    invocation.approval_request_id = approval_request_id;
    let entry = PermissionAuditEntry::evaluate(access_mode, CapabilityKind::BrowserBrowse);
    if !approval_granted || access_request.decision == PolicyDecision::Allow {
        store
            .append_capability_access_request(&access_request)
            .map_err(event_store_error)?;
    }
    store
        .append_permission_audit_entry(&entry)
        .map_err(event_store_error)?;
    store
        .append_capability_invocation(&invocation)
        .map_err(event_store_error)?;

    action.capability_invocation_id = Some(invocation.id);
    action.execution_state = agent_action_state_from_invocation(invocation.status);
    action.dispatch_note = agent_action_dispatch_note(&invocation);
    Ok(())
}

fn open_url_in_chrome_or_default_browser(url: &str) -> Result<BrowserUrlOpenOutcome, String> {
    match open_url_in_chrome(url) {
        Ok(()) => Ok(BrowserUrlOpenOutcome {
            browser_label: "Chrome".to_string(),
            fallback_note: None,
        }),
        Err(chrome_error) => {
            let fallback_note = if chrome_error.contains("could not be found") {
                format!("未检测到 Chrome，已使用默认浏览器打开 {url}")
            } else {
                format!("Chrome 启动失败，已使用默认浏览器打开 {url}")
            };
            open_url_in_default_browser(url)
                .map(|()| BrowserUrlOpenOutcome {
                    browser_label: "default browser".to_string(),
                    fallback_note: Some(fallback_note),
                })
                .map_err(|default_error| {
                    format!("{chrome_error}; default browser fallback also failed: {default_error}")
                })
        }
    }
}

fn open_url_in_chrome(url: &str) -> Result<(), String> {
    let Some(chrome_path) = find_chrome_executable() else {
        return Err("Chrome browser could not be found".to_string());
    };

    Command::new(&chrome_path)
        .arg(url)
        .spawn()
        .map(|_| ())
        .map_err(|error| format!("Chrome could not be launched: {error}"))
}

fn find_chrome_executable() -> Option<PathBuf> {
    let mut candidates = Vec::new();

    if cfg!(target_os = "windows") {
        for variable in [
            "ProgramFiles",
            "PROGRAMFILES",
            "ProgramFiles(x86)",
            "PROGRAMFILES(X86)",
            "LocalAppData",
            "LOCALAPPDATA",
        ] {
            if let Some(base) = std::env::var_os(variable) {
                candidates.push(
                    PathBuf::from(base)
                        .join("Google")
                        .join("Chrome")
                        .join("Application")
                        .join("chrome.exe"),
                );
            }
        }
        candidates.extend(find_executable_on_path(&["chrome.exe", "chrome"]));
    } else if cfg!(target_os = "macos") {
        candidates.push(PathBuf::from(
            "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
        ));
        candidates.extend(find_executable_on_path(&["google-chrome", "chrome"]));
    } else {
        candidates.extend(find_executable_on_path(&[
            "google-chrome",
            "google-chrome-stable",
            "chromium",
            "chromium-browser",
            "chrome",
        ]));
    }

    candidates.into_iter().find(|candidate| candidate.is_file())
}

fn find_executable_on_path(names: &[&str]) -> Vec<PathBuf> {
    let Some(path_value) = std::env::var_os("PATH") else {
        return Vec::new();
    };

    std::env::split_paths(&path_value)
        .flat_map(|directory| {
            names
                .iter()
                .map(move |name| directory.join(name))
                .collect::<Vec<_>>()
        })
        .filter(|candidate| candidate.is_file())
        .collect()
}

fn open_url_in_default_browser(url: &str) -> Result<(), String> {
    let mut command = if cfg!(target_os = "windows") {
        let mut command = Command::new("rundll32");
        command.arg("url.dll,FileProtocolHandler").arg(url);
        command
    } else if cfg!(target_os = "macos") {
        let mut command = Command::new("open");
        command.arg(url);
        command
    } else {
        let mut command = Command::new("xdg-open");
        command.arg(url);
        command
    };

    command
        .spawn()
        .map(|_| ())
        .map_err(|error| format!("default browser URL could not be opened: {error}"))
}

fn agent_action_state_from_invocation(status: CapabilityInvocationStatus) -> String {
    match status {
        CapabilityInvocationStatus::Succeeded => "succeeded",
        CapabilityInvocationStatus::PendingApproval => "needs_confirmation",
        CapabilityInvocationStatus::Failed => "failed",
    }
    .to_string()
}

fn agent_action_state_from_operations_briefing_run(run: &OperationsBriefingRun) -> String {
    match run.status {
        crate::kernel::workflow::OperationsBriefingRunStatus::DraftReady => "succeeded",
        crate::kernel::workflow::OperationsBriefingRunStatus::PendingApproval => {
            "needs_confirmation"
        }
        crate::kernel::workflow::OperationsBriefingRunStatus::Failed => "failed",
    }
    .to_string()
}

fn agent_operations_briefing_dispatch_note(run: &OperationsBriefingRun) -> String {
    let summary = run.summary.trim();
    match run.status {
        crate::kernel::workflow::OperationsBriefingRunStatus::DraftReady => {
            if summary.is_empty() {
                "operations briefing draft ready".to_string()
            } else {
                format!("operations briefing draft ready: {summary}")
            }
        }
        crate::kernel::workflow::OperationsBriefingRunStatus::PendingApproval => {
            "operations briefing waiting for FileRead approval".to_string()
        }
        crate::kernel::workflow::OperationsBriefingRunStatus::Failed => {
            if summary.is_empty() {
                "operations briefing failed".to_string()
            } else {
                format!("operations briefing failed: {summary}")
            }
        }
    }
}

fn agent_action_dispatch_note(invocation: &CapabilityInvocation) -> Option<String> {
    if invocation.capability == CapabilityKind::BrowserBrowse {
        return match invocation.status {
            CapabilityInvocationStatus::Succeeded => {
                if invocation
                    .title
                    .as_deref()
                    .is_some_and(|title| title.starts_with("Browser opened with "))
                {
                    return Some(agent_browser_open_dispatch_note(invocation));
                }

                let target = invocation
                    .title
                    .as_deref()
                    .or(invocation.evidence_url.as_deref())
                    .or(invocation.requested_url.as_deref())
                    .unwrap_or("browser action");
                let url = invocation
                    .evidence_url
                    .as_deref()
                    .or(invocation.requested_url.as_deref());
                Some(match url {
                    Some(url) if target != url => {
                        format!("browser action completed: {target} ({url})")
                    }
                    Some(url) => format!("browser action completed: {url}"),
                    None => format!("browser action completed: {target}"),
                })
            }
            CapabilityInvocationStatus::PendingApproval => {
                Some("browser action waiting for approval".to_string())
            }
            CapabilityInvocationStatus::Failed => invocation
                .warnings
                .first()
                .map(|warning| format!("browser action failed: {warning}"))
                .or_else(|| Some("browser action failed".to_string())),
        };
    }

    if invocation.capability == CapabilityKind::ComputerControl {
        return match invocation.status {
            CapabilityInvocationStatus::Succeeded => invocation
                .excerpt
                .as_deref()
                .map(str::trim)
                .filter(|excerpt| !excerpt.is_empty())
                .map(|excerpt| format!("computer control completed: {excerpt}"))
                .or_else(|| Some("computer control completed".to_string())),
            CapabilityInvocationStatus::PendingApproval => {
                Some("computer control waiting for approval".to_string())
            }
            CapabilityInvocationStatus::Failed => invocation
                .warnings
                .first()
                .map(|warning| format!("computer control failed: {warning}"))
                .or_else(|| Some("computer control failed".to_string())),
        };
    }

    invocation.excerpt.as_deref().map(|excerpt| {
        let action_label = match invocation.capability {
            CapabilityKind::FileRead => "file read",
            CapabilityKind::FileWrite => "file write",
            CapabilityKind::NetworkSearch => "network search",
            _ => "capability action",
        };
        if excerpt.trim().is_empty() {
            format!("{action_label} completed")
        } else {
            format!("{action_label} completed: {}", excerpt.trim())
        }
    })
}

fn agent_browser_open_dispatch_note(invocation: &CapabilityInvocation) -> String {
    if let Some(fallback_note) = invocation
        .warnings
        .iter()
        .find(|warning| warning.contains("默认浏览器"))
    {
        return fallback_note.clone();
    }

    let url = invocation
        .evidence_url
        .as_deref()
        .or(invocation.requested_url.as_deref())
        .unwrap_or("requested URL");
    let title = invocation.title.as_deref().unwrap_or_default();
    if title.contains("Chrome") {
        format!("已使用 Chrome 打开 {url}")
    } else {
        format!("已使用默认浏览器打开 {url}")
    }
}

fn agent_chat_runtime_context(
    app: &AppHandle,
    large_model_provider: LargeModelProvider,
    network_search_source_model: Option<NetworkSearchSourceModel>,
    deepseek_chat_ready: bool,
) -> AgentChatRuntimeContext {
    let app_data_dir = app.resolved_app_data_dir().ok();
    let soul_profile = app_data_dir
        .as_deref()
        .and_then(|app_data_dir| load_agent_soul_profile_context(app_data_dir).ok())
        .flatten();
    let (workspace_ready, workspace_readiness_code, workspace_note, workspace_authority_material) =
        app_data_dir
            .as_deref()
            .and_then(|app_data_dir| load_local_directory_state(app_data_dir).ok())
            .map(|state| {
                let readiness = local_directory_readiness_from_state(&state);
                let projection = workspace_readiness_projection_from_state(&state);
                let authority_material = (projection.code == WorkspaceReadinessCode::Ready)
                    .then(|| state.settings.as_ref())
                    .flatten()
                    .map(|settings| {
                        format!("{}\0{}", settings.workspace_dir, settings.workspace_name)
                            .into_bytes()
                    });
                (
                    if readiness.needs_setup {
                        AgentChatReadiness::Missing
                    } else {
                        AgentChatReadiness::Ready
                    },
                    projection.code,
                    readiness.note,
                    authority_material,
                )
            })
            .unwrap_or_else(|| {
                (
                    AgentChatReadiness::Unknown,
                    WorkspaceReadinessCode::WorkspaceSettingsInvalid,
                    "workspace readiness unavailable".to_string(),
                    None,
                )
            });

    let tool_strategy = model_driven_tool_strategy_for_current_platform(
        large_model_provider,
        network_search_source_model,
    );
    let network_status =
        network_search_route_status_for_strategy(&tool_strategy, deepseek_chat_ready);
    let network_search_ready = if network_status.network_requests_enabled {
        AgentChatReadiness::Ready
    } else {
        AgentChatReadiness::Missing
    };

    AgentChatRuntimeContext {
        active_run_id: None,
        subagent_read_only: false,
        workspace_ready,
        workspace_readiness_code,
        workspace_note,
        workspace_authority_material,
        network_search_ready,
        network_search_note: network_status.note,
        network_search_source_model: tool_strategy.network_search_source_model,
        soul_profile,
        soul_profile_root: app_data_dir,
        memory_context: AgentMemoryRuntimeContext::default(),
        skill_catalog: Vec::new(),
        desktop_dir: app.path().desktop_dir().ok(),
        expert_staging_root: None,
        expert_capabilities: None,
    }
}

