    #[test]
    fn durable_computer_use_tool_request_is_exact_and_discloses_post_verification() {
        let now = Utc::now();
        let pre = ComputerUseObservation::new(
            ComputerUseObservationPhase::PreAction,
            "a".repeat(64),
            "e".repeat(64),
            Some("b".repeat(64)),
            Some("c".repeat(64)),
            "computer-screenshots/pre.png".to_string(),
            "Isolated editor is foreground and focused.".to_string(),
            now,
        )
        .unwrap();
        let binding = ComputerUseActionBinding::new(
            &pre,
            ComputerControlAction::TypeText {
                text: "private approved text".to_string(),
            },
            "Type the exact approved text into the isolated editor.".to_string(),
            ComputerUsePostcondition::TargetSemanticFingerprintEquals {
                expected: "d".repeat(64),
            },
        )
        .unwrap();
        let action_fingerprint = binding.action_fingerprint.clone();
        let mut step = ComputerUseStep::new_observed(
            Uuid::new_v4(),
            1,
            pre,
            ComputerUseUndoCapability::None,
            now,
        )
        .unwrap();
        step.bind_action(binding, now).unwrap();

        let request = durable_computer_use_tool_request(&step, AccessMode::FullAccess).unwrap();
        assert_eq!(request.tool_id, COMPUTER_CONTROL_TOOL_ID);
        assert_eq!(
            request.input["target"],
            json!("foreground accessibility target")
        );
        assert_eq!(request.input["action"], json!("type:private approved text"));
        let summary = request.input["summary"].as_str().unwrap();
        assert!(summary.contains(&action_fingerprint));
        assert!(summary.contains("Automatic post-action screenshot"));
    }

    #[test]
    fn durable_computer_use_accepts_only_recent_succeeded_screenshot_evidence() {
        let store = EventStore::open_memory().expect("memory store opens");
        let valid_id = Uuid::new_v4();
        store
            .append_capability_invocation(&CapabilityInvocation {
                id: valid_id,
                capability: CapabilityKind::ComputerScreenshot,
                status: CapabilityInvocationStatus::Succeeded,
                policy_decision: PolicyDecision::Ask,
                approval_request_id: Some(Uuid::new_v4()),
                requested_resource: Some("visible desktop screenshot".to_string()),
                evidence_ref: Some("computer-screenshots/recent.png".to_string()),
                requested_url: None,
                evidence_url: None,
                title: Some("Recent screenshot".to_string()),
                excerpt: None,
                warnings: Vec::new(),
                elapsed_ms: 1,
                created_at: Utc::now(),
            })
            .unwrap();
        assert_eq!(
            resolved_computer_use_screenshot(&store, valid_id)
                .unwrap()
                .0,
            "computer-screenshots/recent.png"
        );

        let stale_id = Uuid::new_v4();
        store
            .append_capability_invocation(&CapabilityInvocation {
                id: stale_id,
                capability: CapabilityKind::ComputerScreenshot,
                status: CapabilityInvocationStatus::Succeeded,
                policy_decision: PolicyDecision::Ask,
                approval_request_id: Some(Uuid::new_v4()),
                requested_resource: Some("visible desktop screenshot".to_string()),
                evidence_ref: Some("computer-screenshots/stale.png".to_string()),
                requested_url: None,
                evidence_url: None,
                title: Some("Stale screenshot".to_string()),
                excerpt: None,
                warnings: Vec::new(),
                elapsed_ms: 1,
                created_at: Utc::now()
                    - Duration::seconds(super::COMPUTER_USE_SCREENSHOT_MAX_AGE_SECONDS + 1),
            })
            .unwrap();
        assert!(resolved_computer_use_screenshot(&store, stale_id)
            .unwrap_err()
            .contains("stale"));
    }

    #[test]
    fn computer_control_write_lease_blocks_screenshot_until_execution_finishes() {
        let store = EventStore::open_memory().expect("memory store opens");
        let control_client = RecordingComputerControlClient::new();
        let screenshot_client = RecordingComputerScreenshotClient::new(
            1600,
            900,
            "computer-screenshots/after-control.png",
        );
        let control_request = ToolExecutionRequest {
            tool_id: COMPUTER_CONTROL_TOOL_ID.to_string(),
            input: json!({
                "target": "Word",
                "action": "click:10,20,left",
                "summary": "Hold the foreground desktop writer."
            }),
            access_mode: AccessMode::FullAccess,
            run_id: None,
        };
        let waiting = execute_agent_tool_with_executor(
            &store,
            control_request.clone(),
            &ComputerControlAgentToolExecutor {
                client: &control_client,
            },
        )
        .expect("control waits for approval");
        let approval_request_id = waiting
            .approval_request_id
            .expect("control approval is linked");
        store
            .resolve_capability_access_request(
                approval_request_id,
                true,
                "Approved exact control writer.".to_string(),
            )
            .expect("approval resolves");
        let control = authorize_agent_tool_execution(&store, control_request)
            .expect("approved control authorizes");
        let control = match control {
            AgentToolAuthorization::Ready(authorized) => authorized,
            AgentToolAuthorization::Finished(_) => panic!("control should hold the desktop writer"),
        };

        let blocked_screenshot = execute_agent_tool_with_executor(
            &store,
            ToolExecutionRequest {
                tool_id: COMPUTER_SCREENSHOT_TOOL_ID.to_string(),
                input: json!({"summary": "Do not race the active input action."}),
                access_mode: AccessMode::LimitedAuto,
                run_id: None,
            },
            &ComputerScreenshotAgentToolExecutor {
                client: &screenshot_client,
            },
        )
        .expect("screenshot conflict is audited");

        assert_eq!(blocked_screenshot.status, ToolExecutionStatus::Blocked);
        assert!(blocked_screenshot
            .error
            .as_deref()
            .is_some_and(|error| error.contains("resource")));
        assert_eq!(screenshot_client.calls.get(), 0);

        let control = run_authorized_agent_tool_execution(
            control,
            &ComputerControlAgentToolExecutor {
                client: &control_client,
            },
        );
        record_completed_agent_tool_execution(&store, &control).expect("control completes");
        assert_eq!(control.status, ToolExecutionStatus::Succeeded);

        let screenshot = execute_agent_tool_with_executor(
            &store,
            ToolExecutionRequest {
                tool_id: COMPUTER_SCREENSHOT_TOOL_ID.to_string(),
                input: json!({"summary": "Capture state after the input action."}),
                access_mode: AccessMode::LimitedAuto,
                run_id: None,
            },
            &ComputerScreenshotAgentToolExecutor {
                client: &screenshot_client,
            },
        )
        .expect("screenshot executes after writer release");

        assert_eq!(screenshot.status, ToolExecutionStatus::Succeeded);
        assert_eq!(screenshot_client.calls.get(), 1);
    }

