    impl SequencedDeepSeekTransport {
        fn new(responses: Vec<String>) -> Self {
            Self {
                responses: Mutex::new(responses.into_iter().map(Ok).collect()),
                requests: Mutex::new(Vec::new()),
            }
        }

        fn new_results(responses: Vec<Result<String, String>>) -> Self {
            Self {
                responses: Mutex::new(responses),
                requests: Mutex::new(Vec::new()),
            }
        }

        fn recorded_requests(&self) -> Vec<DeepSeekChatCompletionRequest> {
            self.requests
                .lock()
                .map(|requests| requests.clone())
                .unwrap_or_default()
        }
    }

    impl DeepSeekChatCompletionTransport for SequencedDeepSeekTransport {
        fn post_chat_completion(
            &self,
            _endpoint: &str,
            _api_key: &str,
            request: &DeepSeekChatCompletionRequest,
        ) -> Result<DeepSeekChatCompletionResponse, String> {
            self.requests
                .lock()
                .expect("record requests")
                .push(request.clone());
            let response_text = {
                let mut responses = self.responses.lock().expect("read response sequence");
                if responses.is_empty() {
                    return Err("no fake DeepSeek response left".to_string());
                }
                responses.remove(0)
            };
            match response_text {
                Ok(response_text) => Ok(DeepSeekChatCompletionResponse::from_text(
                    request.model.clone(),
                    response_text,
                )),
                Err(error) => Err(error),
            }
        }
    }

    impl<'a> StoreLockCheckingDeepSeekTransport<'a> {
        fn new(store: &'a Mutex<EventStore>, response_text: impl Into<String>) -> Self {
            Self {
                store,
                response_text: response_text.into(),
                lock_available_at_call: Mutex::new(Vec::new()),
            }
        }

        fn lock_checks(&self) -> Vec<bool> {
            self.lock_available_at_call
                .lock()
                .map(|checks| checks.clone())
                .unwrap_or_default()
        }
    }

    impl DeepSeekChatCompletionTransport for StoreLockCheckingDeepSeekTransport<'_> {
        fn post_chat_completion(
            &self,
            _endpoint: &str,
            _api_key: &str,
            request: &DeepSeekChatCompletionRequest,
        ) -> Result<DeepSeekChatCompletionResponse, String> {
            let lock_available = self.store.try_lock().is_ok();
            self.lock_available_at_call
                .lock()
                .expect("record lock check")
                .push(lock_available);
            if !lock_available {
                return Err("event store lock was held during DeepSeek call".to_string());
            }

            Ok(DeepSeekChatCompletionResponse::from_text(
                request.model.clone(),
                self.response_text.clone(),
            ))
        }
    }

    impl<'a> CancelingDeepSeekTransport<'a> {
        fn new(
            store: &'a Mutex<EventStore>,
            run_id: Uuid,
            response_text: impl Into<String>,
        ) -> Self {
            Self::new_on_call(store, run_id, response_text, 1)
        }

        fn new_on_call(
            store: &'a Mutex<EventStore>,
            run_id: Uuid,
            response_text: impl Into<String>,
            cancel_on_call: usize,
        ) -> Self {
            Self {
                store,
                run_id,
                response_text: response_text.into(),
                cancel_on_call,
                call_count: Mutex::new(0),
            }
        }
    }

    impl DeepSeekChatCompletionTransport for CancelingDeepSeekTransport<'_> {
        fn post_chat_completion(
            &self,
            _endpoint: &str,
            _api_key: &str,
            request: &DeepSeekChatCompletionRequest,
        ) -> Result<DeepSeekChatCompletionResponse, String> {
            let call_count = {
                let mut call_count = self.call_count.lock().expect("call count lock");
                *call_count += 1;
                *call_count
            };
            if call_count == self.cancel_on_call {
                let cancel =
                    AgentRunCancelRequest::new(self.run_id, "用户取消了后台任务。".to_string())
                        .expect("cancel request");
                self.store
                    .lock()
                    .expect("store lock")
                    .append_agent_run_cancel_request(&cancel)
                    .expect("cancel request appends");
            }
            Ok(DeepSeekChatCompletionResponse::from_text(
                request.model.clone(),
                self.response_text.clone(),
            ))
        }
    }

    impl<'a> GuidanceQueueingDeepSeekTransport<'a> {
        fn new(
            store: &'a Mutex<EventStore>,
            run_id: Uuid,
            guidance: impl Into<String>,
            responses: Vec<String>,
        ) -> Self {
            Self {
                store,
                run_id,
                guidance: guidance.into(),
                responses: Mutex::new(responses),
                requests: Mutex::new(Vec::new()),
                call_count: Mutex::new(0),
                queued_guidance_id: Mutex::new(None),
            }
        }

        fn recorded_requests(&self) -> Vec<DeepSeekChatCompletionRequest> {
            self.requests
                .lock()
                .map(|requests| requests.clone())
                .unwrap_or_default()
        }

        fn queued_guidance_id(&self) -> Option<Uuid> {
            self.queued_guidance_id.lock().ok().and_then(|id| *id)
        }
    }

    impl DeepSeekChatCompletionTransport for GuidanceQueueingDeepSeekTransport<'_> {
        fn post_chat_completion(
            &self,
            _endpoint: &str,
            _api_key: &str,
            request: &DeepSeekChatCompletionRequest,
        ) -> Result<DeepSeekChatCompletionResponse, String> {
            self.requests
                .lock()
                .expect("record requests")
                .push(request.clone());
            let call_count = {
                let mut call_count = self.call_count.lock().expect("call count lock");
                *call_count += 1;
                *call_count
            };
            if call_count == 1 {
                let guidance = AgentRunQueuedGuidance::new(self.run_id, self.guidance.clone())
                    .expect("queued guidance is valid");
                self.store
                    .lock()
                    .expect("store lock")
                    .append_agent_run_queued_guidance(&guidance)
                    .expect("guidance appends");
                *self.queued_guidance_id.lock().expect("guidance id lock") = Some(guidance.id);
            }
            let response_text = {
                let mut responses = self.responses.lock().expect("response lock");
                if responses.is_empty() {
                    return Err("no fake DeepSeek response left".to_string());
                }
                responses.remove(0)
            };
            Ok(DeepSeekChatCompletionResponse::from_text(
                request.model.clone(),
                response_text,
            ))
        }
    }

